"""
Lazy yfinance wrapper with graceful fallbacks.

This module provides a safe way to use yfinance that:
1. Handles import failures gracefully (for CI compatibility)
2. Provides mock data when yfinance is unavailable
3. Caches data to reduce API calls
4. Falls back to Alpaca for stock data when possible

Usage:
    from src.utils.yfinance_wrapper import get_vix, get_ticker, is_available

    if is_available():
        vix = get_vix()
    else:
        vix = get_vix()  # Returns mock/cached data
"""

from __future__ import annotations

import json
import logging
import os
from datetime import datetime, timedelta
from pathlib import Path
from typing import Any

logger = logging.getLogger(__name__)

# Lazy pandas import
_pandas = None


def _get_pandas():
    """Lazy import pandas."""
    global _pandas
    if _pandas is None:
        try:
            import pandas as pd

            _pandas = pd
        except ImportError:
            logger.warning("pandas not available - returning empty data structures")
            _pandas = False
    return _pandas if _pandas else None


# Lazy import state
_yfinance = None
_import_attempted = False
_import_error: str | None = None

# Cache directory for offline/CI mode
CACHE_DIR = Path("data/market_cache")
CACHE_DIR.mkdir(parents=True, exist_ok=True)

# Default VIX values for when data is unavailable
DEFAULT_VIX = 18.0  # Long-term average
DEFAULT_VVIX = 90.0  # Long-term average
DEFAULT_VXV = 20.0  # 3-month VIX average


def _try_import_yfinance():
    """Attempt to import yfinance, caching the result."""
    global _yfinance, _import_attempted, _import_error

    if _import_attempted:
        return _yfinance

    _import_attempted = True

    try:
        import yfinance as yf

        _yfinance = yf
        logger.debug("yfinance imported successfully")
    except ImportError as e:
        _import_error = str(e)
        logger.warning(f"yfinance not available: {e}. Using fallback data.")
    except Exception as e:
        _import_error = str(e)
        logger.warning(f"yfinance import failed: {e}. Using fallback data.")

    return _yfinance


def is_available() -> bool:
    """Check if yfinance is available for use."""
    _try_import_yfinance()
    return _yfinance is not None


def get_import_error() -> str | None:
    """Get the import error message if yfinance failed to import."""
    _try_import_yfinance()
    return _import_error


def _load_cached_value(key: str) -> dict | None:
    """Load a cached value if it exists and is fresh (< 1 hour old)."""
    cache_file = CACHE_DIR / f"{key}.json"
    if cache_file.exists():
        try:
            with open(cache_file) as f:
                data = json.load(f)
            cached_time = datetime.fromisoformat(data.get("timestamp", "2000-01-01"))
            if datetime.now() - cached_time < timedelta(hours=1):
                return data
        except Exception:
            pass
    return None


def _save_cached_value(key: str, value: float, extra: dict | None = None):
    """Save a value to cache."""
    cache_file = CACHE_DIR / f"{key}.json"
    try:
        data = {
            "value": value,
            "timestamp": datetime.now().isoformat(),
            **(extra or {}),
        }
        with open(cache_file, "w") as f:
            json.dump(data, f)
    except Exception as e:
        logger.debug(f"Failed to cache {key}: {e}")


def get_vix(use_cache: bool = True) -> float:
    """
    Get current VIX value with fallbacks.

    Priority:
    1. Live yfinance data (if available)
    2. Cached data (if fresh)
    3. Environment variable VIX_OVERRIDE
    4. Default value (18.0)
    """
    # Check environment override (useful for testing)
    env_vix = os.environ.get("VIX_OVERRIDE")
    if env_vix:
        try:
            return float(env_vix)
        except ValueError:
            pass

    # Try cache first if requested
    if use_cache:
        cached = _load_cached_value("vix")
        if cached:
            logger.debug(f"Using cached VIX: {cached['value']}")
            return cached["value"]

    # Try yfinance
    yf = _try_import_yfinance()
    if yf:
        try:
            vix = yf.Ticker("^VIX")
            hist = vix.history(period="1d")
            if not hist.empty:
                value = float(hist["Close"].iloc[-1])
                _save_cached_value("vix", value)
                logger.debug(f"Live VIX: {value}")
                return value
        except Exception as e:
            logger.warning(f"Failed to fetch VIX: {e}")

    # Return default
    logger.info(f"Using default VIX: {DEFAULT_VIX}")
    return DEFAULT_VIX


def get_vvix(use_cache: bool = True) -> float:
    """Get current VVIX (VIX of VIX) with fallbacks."""
    env_vvix = os.environ.get("VVIX_OVERRIDE")
    if env_vvix:
        try:
            return float(env_vvix)
        except ValueError:
            pass

    if use_cache:
        cached = _load_cached_value("vvix")
        if cached:
            return cached["value"]

    yf = _try_import_yfinance()
    if yf:
        try:
            vvix = yf.Ticker("^VVIX")
            hist = vvix.history(period="1d")
            if not hist.empty:
                value = float(hist["Close"].iloc[-1])
                _save_cached_value("vvix", value)
                return value
        except Exception as e:
            logger.warning(f"Failed to fetch VVIX: {e}")

    return DEFAULT_VVIX


def get_vxv(use_cache: bool = True) -> float:
    """Get current VXV (3-month VIX) with fallbacks."""
    env_vxv = os.environ.get("VXV_OVERRIDE")
    if env_vxv:
        try:
            return float(env_vxv)
        except ValueError:
            pass

    if use_cache:
        cached = _load_cached_value("vxv")
        if cached:
            return cached["value"]

    yf = _try_import_yfinance()
    if yf:
        try:
            vxv = yf.Ticker("^VXV")
            hist = vxv.history(period="1d")
            if not hist.empty:
                value = float(hist["Close"].iloc[-1])
                _save_cached_value("vxv", value)
                return value
        except Exception as e:
            logger.warning(f"Failed to fetch VXV: {e}")

    return DEFAULT_VXV


def get_ticker(symbol: str):
    """
    Get a yfinance Ticker object or a mock equivalent.

    Returns a real Ticker if yfinance is available, otherwise returns
    a MockTicker that provides safe default values.
    """
    yf = _try_import_yfinance()
    if yf:
        return yf.Ticker(symbol)
    return MockTicker(symbol)


def download(
    tickers: str | list[str],
    start: str | None = None,
    end: str | None = None,
    period: str = "1mo",
    interval: str = "1d",
    **kwargs,
):
    """
    Download historical data with fallbacks.

    Mirrors yfinance.download() signature but handles unavailability gracefully.
    Returns pandas DataFrame if available, empty dict otherwise.
    """
    yf = _try_import_yfinance()
    if yf:
        try:
            return yf.download(
                tickers,
                start=start,
                end=end,
                period=period,
                interval=interval,
                **kwargs,
            )
        except Exception as e:
            logger.warning(f"yfinance download failed: {e}")

    # Return empty DataFrame with expected structure
    pd = _get_pandas()
    logger.warning(f"Returning empty DataFrame for {tickers}")
    if pd:
        return pd.DataFrame(columns=["Open", "High", "Low", "Close", "Volume", "Adj Close"])
    return {}


class MockTicker:
    """
    Mock yfinance Ticker for when yfinance is unavailable.

    Provides safe default values that won't crash the system.
    """

    def __init__(self, symbol: str):
        self.symbol = symbol
        self._info_cache: dict[str, Any] | None = None

    @property
    def info(self) -> dict[str, Any]:
        """Return mock info dict."""
        if self._info_cache:
            return self._info_cache

        logger.warning(
            "MockTicker used for %s — yfinance unavailable. "
            "Price data will be ZERO to prevent bad calculations.",
            self.symbol,
        )
        self._info_cache = {
            "symbol": self.symbol,
            "shortName": f"{self.symbol} (MOCK - NO REAL DATA)",
            "regularMarketPrice": 0.0,
            "previousClose": 0.0,
            "volume": 0,
            "marketCap": 0,
            "trailingPE": None,
            "forwardPE": None,
            "dividendYield": None,
            "_mock": True,
        }
        return self._info_cache

    def history(
        self,
        period: str = "1mo",
        start: str | None = None,
        end: str | None = None,
        interval: str = "1d",
        **kwargs,
    ):
        """Return empty DataFrame for history."""
        logger.debug(f"MockTicker.history() called for {self.symbol}")
        pd = _get_pandas()
        if pd:
            return pd.DataFrame(columns=["Open", "High", "Low", "Close", "Volume"])
        return {}

    @property
    def options(self) -> tuple:
        """Return empty options chain dates."""
        return tuple()

    def option_chain(self, date: str | None = None):
        """Return mock option chain."""
        return MockOptionChain()

    @property
    def financials(self):
        """Return empty financials."""
        pd = _get_pandas()
        return pd.DataFrame() if pd else {}

    @property
    def quarterly_financials(self):
        """Return empty quarterly financials."""
        pd = _get_pandas()
        return pd.DataFrame() if pd else {}

    @property
    def earnings_dates(self):
        """Return empty earnings dates."""
        pd = _get_pandas()
        return pd.DataFrame() if pd else {}

    @property
    def calendar(self) -> dict:
        """Return empty calendar."""
        return {}


class MockOptionChain:
    """Mock option chain for when yfinance is unavailable."""

    def __init__(self):
        pd = _get_pandas()
        cols = [
            "contractSymbol",
            "strike",
            "lastPrice",
            "bid",
            "ask",
            "volume",
            "openInterest",
            "impliedVolatility",
        ]
        if pd:
            self.calls = pd.DataFrame(columns=cols)
            self.puts = pd.DataFrame(columns=cols)
        else:
            self.calls = {}
            self.puts = {}


# Convenience aliases
Ticker = get_ticker

"""Lessons learned RAG with LanceDB-first retrieval and keyword fallback.

Updated Feb 9, 2026: LanceDB-first semantic retrieval with keyword fallback.
"""

import logging
import os
from pathlib import Path
from typing import Optional

logger = logging.getLogger(__name__)

# Optional LanceDB semantic search
try:
    from src.memory.document_aware_rag import get_document_aware_rag

    LANCEDB_RAG_AVAILABLE = True
except ImportError:
    LANCEDB_RAG_AVAILABLE = False
    logger.warning("DocumentAwareRAG not available")

# Use the simplified LessonsSearch
try:
    from src.rag.lessons_search import get_lessons_search

    LESSONS_SEARCH_AVAILABLE = True
except ImportError:
    LESSONS_SEARCH_AVAILABLE = False
    logger.warning("LessonsSearch not available")


class LessonsLearnedRAG:
    """RAG for lessons learned with LanceDB-first retrieval."""

    def __init__(self, knowledge_dir: Optional[str] = None):
        self.knowledge_dir = Path(knowledge_dir or "rag_knowledge/lessons_learned")
        self._custom_dir = knowledge_dir is not None
        self.lessons = []
        self.last_source = "none"

        # LanceDB-first retrieval (semantic)
        self.lancedb_rag = None
        self.lancedb_enabled = os.getenv("LANCEDB_RAG", "true").lower() in {
            "1",
            "true",
            "yes",
        }
        if self._custom_dir:
            # Custom knowledge dirs are not indexed in LanceDB; force local search.
            self.lancedb_enabled = False
        self.lancedb_required = os.getenv("LANCEDB_REQUIRED", "false").lower() in {
            "1",
            "true",
            "yes",
        }
        # NOTE: Previously forced lancedb_required=True in CI, which crashed
        # the entire TradingOrchestrator when LanceDB wasn't installed (Feb 10-13 outage).
        # Trading must never be blocked by a search index failure.
        self.lancedb_auto_index = os.getenv("LANCEDB_AUTO_INDEX", "true").lower() in {
            "1",
            "true",
            "yes",
        }
        if self.lancedb_enabled:
            if not LANCEDB_RAG_AVAILABLE:
                if self.lancedb_required:
                    raise RuntimeError("LanceDB required but DocumentAwareRAG not available")
                logger.warning("DocumentAwareRAG not available; falling back to keyword search")
            else:
                try:
                    self.lancedb_rag = get_document_aware_rag()
                    if self.lancedb_auto_index or self.lancedb_required:
                        status = self.lancedb_rag.ensure_index()
                        if status.get("error"):
                            raise RuntimeError(f"LanceDB index unavailable: {status['error']}")
                    logger.info("✅ LanceDB RAG initialized (primary)")
                except Exception as e:
                    if self.lancedb_required:
                        raise
                    logger.warning(f"LanceDB RAG init failed: {e}")
                    self.lancedb_rag = None

        # Use LessonsSearch for keyword-based search
        if LESSONS_SEARCH_AVAILABLE and not self._custom_dir:
            try:
                self.search_engine = get_lessons_search()
                logger.info(
                    f"✅ LessonsSearch initialized with {self.search_engine.count()} lessons"
                )
                # Still load lessons for compatibility
                self._load_lessons()
                return
            except Exception as e:
                logger.warning(
                    f"LessonsSearch initialization failed: {e} - using direct file search"
                )
        elif self._custom_dir:
            logger.info(
                "Custom knowledge dir provided; skipping LessonsSearch and using direct file search."
            )

        # Fallback to direct file-based search
        self.search_engine = None
        self._load_lessons()

    def _load_lessons(self) -> None:
        """Load all lessons from markdown files."""
        if not self.knowledge_dir.exists():
            logger.warning(f"Lessons directory not found: {self.knowledge_dir}")
            return

        for lesson_file in self.knowledge_dir.glob("*.md"):
            try:
                content = lesson_file.read_text()
                # Parse basic metadata
                lesson = {
                    "id": lesson_file.stem,
                    "file": str(lesson_file),
                    "content": content,
                    "severity": self._extract_severity(content),
                    "tags": self._extract_tags(content),
                }
                self.lessons.append(lesson)
            except Exception as e:
                logger.warning(f"Failed to load lesson {lesson_file}: {e}")

        logger.info(f"Loaded {len(self.lessons)} lessons from {self.knowledge_dir}")

    def _extract_severity(self, content: str) -> str:
        """Extract severity from lesson content."""
        content_lower = content.lower()
        if "severity**: critical" in content_lower:
            return "CRITICAL"
        elif "severity**: high" in content_lower:
            return "HIGH"
        elif "severity**: medium" in content_lower:
            return "MEDIUM"
        return "LOW"

    def _extract_tags(self, content: str) -> list:
        """Extract tags from lesson content."""
        import re

        match = re.search(r"`([^`]+)`(?:,\s*`([^`]+)`)*\s*$", content, re.MULTILINE)
        if match:
            tags_line = content.split("## Tags")[-1] if "## Tags" in content else ""
            return re.findall(r"`([^`]+)`", tags_line)
        return []

    def _query_lancedb(self, query: str, top_k: int = 5) -> list[dict]:
        if self.lancedb_rag is None:
            return []

        expansions = {
            "exit": ["time exit", "7 dte", "profit target"],
            "position sizing": ["position limit", "position accumulation", "accumulation"],
            "close position": ["close_position", "closing position", "close positions"],
            "delta selection": ["delta", "15 delta", "20 delta"],
            "api bug": ["alpaca", "close_position"],
        }
        expanded_terms = []
        lowered_query = query.lower()
        for key, terms in expansions.items():
            if key in lowered_query:
                expanded_terms.extend(terms)

        expanded_query = query
        if expanded_terms:
            expanded_query = f"{query} {' '.join(expanded_terms)}"

        candidate_limit = max(top_k * 8, 40)
        results = self.lancedb_rag.search(expanded_query, limit=candidate_limit)

        query_terms = [
            t
            for t in expanded_query.lower().split()
            if len(t) > 2
            and t
            not in {
                "the",
                "and",
                "for",
                "with",
                "from",
                "that",
                "this",
                "into",
                "over",
                "your",
                "you",
                "our",
                "are",
                "was",
                "were",
                "why",
                "how",
            }
        ]

        formatted = []
        for r in results:
            source = r.metadata.get("source", "") if r.metadata else ""
            if "rag_knowledge/lessons_learned" not in source:
                continue

            lesson_id = r.metadata.get("lesson_id") or r.document_id
            severity = (r.metadata.get("severity") or "LOW").upper()
            content = r.content or ""
            snippet = content[:500]
            raw_score = None
            if r.metadata:
                raw_score = r.metadata.get("raw_score")

            title = r.title or ""
            content_lower = content.lower()
            title_lower = title.lower()
            lesson_id_lower = str(lesson_id).lower()
            boost = 0.0
            for term in query_terms:
                if term in title_lower:
                    boost += 0.1
                if term in content_lower:
                    boost += 0.05
                if term in lesson_id_lower:
                    boost += 0.08

            combined_score = (r.score or 0.0) + boost

            formatted.append(
                {
                    "id": lesson_id,
                    "severity": severity,
                    "score": combined_score,
                    "raw_score": raw_score if raw_score is not None else r.score,
                    "snippet": snippet,
                    "content": content,
                    "file": source,
                    "title": title,
                    "prevention": "",
                }
            )

        if not formatted:
            return []

        # Deduplicate by lesson_id, keeping the highest score
        deduped = {}
        for item in formatted:
            key = str(item["id"]).lower()
            existing = deduped.get(key)
            if existing is None or item["score"] > existing["score"]:
                deduped[key] = item

        ranked = sorted(deduped.values(), key=lambda x: x["score"], reverse=True)
        return ranked[:top_k]

    def query(self, query: str, top_k: int = 5, severity_filter: Optional[str] = None) -> list:
        """Search lessons using LanceDB first, then keyword matching."""
        if self.lancedb_rag is not None:
            try:
                results = self._query_lancedb(query, top_k=top_k)
                if results:
                    if severity_filter:
                        results = [r for r in results if r.get("severity") == severity_filter][
                            :top_k
                        ]
                    self.last_source = "lancedb"
                    return self._reposition_results(query, results, top_k)
            except Exception as e:
                logger.warning(f"LanceDB query failed: {e} - using keyword fallback")

        # Use LessonsSearch if available
        if self.search_engine is not None:
            try:
                results = self.search_engine.search(
                    query, top_k=top_k, severity_filter=severity_filter
                )
                # Convert results to expected format
                self.last_source = "keyword"
                formatted = [
                    {
                        "id": lesson.id,
                        "severity": lesson.severity,
                        "score": score,
                        "snippet": lesson.snippet,
                        "content": lesson.snippet,  # Use snippet as content
                        "file": lesson.file,
                        "title": lesson.title,
                        "prevention": lesson.prevention,
                    }
                    for lesson, score in results
                ]
                return self._reposition_results(query, formatted, top_k)
            except Exception as e:
                logger.warning(f"LessonsSearch failed: {e} - using direct file search")

        # Fallback: keyword-based search
        if not self.lessons:
            return []

        query_terms = query.lower().split()
        results = []

        for lesson in self.lessons:
            # Filter by severity if specified
            if severity_filter and lesson["severity"] != severity_filter:
                continue

            content_lower = lesson["content"].lower()
            lesson_id = lesson["id"].lower()

            # Score based on term matches
            score = 0
            for term in query_terms:
                if term in content_lower:
                    score += content_lower.count(term)
                # Boost for matches in tags
                if any(term in tag.lower() for tag in lesson["tags"]):
                    score += 5

            # Boost CRITICAL lessons
            if lesson["severity"] == "CRITICAL":
                score *= 2

            # RECENCY BOOST: Prioritize recent content (but don't PENALIZE old lessons)
            # CRITICAL lessons from any date should still be findable
            if "jan11" in lesson_id or "jan10" in lesson_id or "jan09" in lesson_id:
                score *= 2.0  # Boost recent lessons
            elif "jan" in lesson_id:
                score *= 1.5  # Moderate boost for January
            elif "trading_rules" in lesson_id or "2026" in lesson_id:
                score *= 2.0  # Boost actionable rules
            # Note: Old lessons are NOT penalized - we need to find CRITICAL lessons from any date

            if score > 0:
                # Normalize score to 0-1 range for consistency with ChromaDB
                normalized_score = min(score / 50.0, 1.0)
                results.append(
                    {
                        "id": lesson["id"],
                        "severity": lesson["severity"],
                        "score": normalized_score,
                        "snippet": lesson["content"][:500],
                        "content": lesson["content"],
                        "file": lesson["file"],
                    }
                )

        # Sort by score descending
        results.sort(key=lambda x: x["score"], reverse=True)
        self.last_source = "keyword"
        return self._reposition_results(query, results, top_k)

    def _reposition_results(self, query: str, results: list[dict], top_k: int) -> list[dict]:
        """Re-rank lessons to keep the most relevant context close and diverse."""
        if not results:
            return []
        try:
            from src.rag.context_repositioning import reposition_lessons

            return reposition_lessons(query, results, top_k)
        except Exception as exc:  # pragma: no cover - non-critical enhancement
            logger.debug(f"Context repositioning skipped: {exc}")
            return results[:top_k]

    def search(self, query: str, top_k: int = 5) -> list:
        """
        Search lessons - returns format expected by gates.py and main.py.

        Returns list of (LessonResult, score) tuples for compatibility.
        """
        from dataclasses import dataclass

        @dataclass
        class LessonResult:
            id: str
            title: str
            severity: str
            snippet: str
            prevention: str  # Required by gates.py and main.py
            file: str

        raw_results = self.query(query, top_k=top_k)
        results = []
        for r in raw_results:
            # Extract prevention section from content or use snippet as fallback
            prevention = r.get("prevention") or self._extract_prevention(
                r.get("content", r["snippet"])
            )
            lesson = LessonResult(
                id=r["id"],
                title=r.get("title", r["id"]),
                severity=r["severity"],
                snippet=r["snippet"],
                prevention=prevention,
                file=r["file"],
            )
            # Score is already normalized to 0-1 range by query()
            results.append((lesson, r["score"]))
        return results

    def _extract_prevention(self, content: str) -> str:
        """Extract prevention/action section from lesson content."""
        import re

        # Try to find Prevention, Action, or Solution section
        patterns = [
            r"## Prevention\s*\n(.*?)(?=\n##|\Z)",
            r"## Action\s*\n(.*?)(?=\n##|\Z)",
            r"## Solution\s*\n(.*?)(?=\n##|\Z)",
            r"## What to Do\s*\n(.*?)(?=\n##|\Z)",
            r"## Fix\s*\n(.*?)(?=\n##|\Z)",
        ]
        for pattern in patterns:
            match = re.search(pattern, content, re.DOTALL | re.IGNORECASE)
            if match:
                return match.group(1).strip()[:500]

        # Fallback: use first 300 chars of content
        return content[:300].strip()

    def get_critical_lessons(self) -> list:
        """Get all CRITICAL severity lessons."""
        return [lesson for lesson in self.lessons if lesson["severity"] == "CRITICAL"]

    def add_lesson(self, lesson_id: str, content: str) -> None:
        """Add a new lesson (writes to file)."""
        lesson_file = self.knowledge_dir / f"{lesson_id}.md"
        lesson_file.write_text(content)
        self._load_lessons()  # Reload

