def _compute_no_trade_diagnostic(
    *,
    data_dir: Path,
    state: dict[str, Any],
    recent_decisions: list[dict[str, Any]],
    closed_trades_recent: int,
    qualified_setups_recent: int,
    min_liquidity_volume_ratio: float = DEFAULT_MIN_LIQUIDITY_VOLUME_RATIO,
) -> dict[str, Any]:
    workflow_state_dir = data_dir / "workflow_state"
    iron_condor_state = _load_json_dict(workflow_state_dir / "iron_condor_pipeline_state.json")
    swarm_state = _load_json_dict(workflow_state_dir / "swarm_integrated_pipeline_state.json")

    iron_regime = _safe_nested_dict(iron_condor_state, "results", "regime_gate", "output")
    options_chain = _safe_nested_dict(iron_condor_state, "results", "options_chain", "output")
    swarm_risk = _safe_nested_dict(swarm_state, "results", "risk_gate", "output")
    risk_checks = (
        swarm_risk.get("risk_checks", {}) if isinstance(swarm_risk.get("risk_checks"), dict) else {}
    )
    regime_check = (
        risk_checks.get("regime_check", {})
        if isinstance(risk_checks.get("regime_check"), dict)
        else {}
    )
    position_size_check = (
        risk_checks.get("position_size_check", {})
        if isinstance(risk_checks.get("position_size_check"), dict)
        else {}
    )

    rejection_reasons = [str(row.get("rejection_reason", "")).strip() for row in recent_decisions]
    rejection_reasons = [text for text in rejection_reasons if text]
    reason_counter = Counter(rejection_reasons)
    category_counter = Counter()
    for reason in rejection_reasons:
        for category in _categorize_reason(reason):
            category_counter[category] += 1

    volume_ratios = [
        float(row["volume_ratio"])
        for row in recent_decisions
        if isinstance(row.get("volume_ratio"), (int, float))
    ]
    low_liquidity_events = sum(1 for ratio in volume_ratios if ratio < min_liquidity_volume_ratio)
    avg_volume_ratio = round(sum(volume_ratios) / len(volume_ratios), 4) if volume_ratios else None

    dte_raw = _safe_nested_dict(options_chain, "data").get("recommended_dte")
    dte_value = _as_int(dte_raw, 0) if dte_raw is not None else None

    regime_pass_signal: bool | None = None
    if isinstance(regime_check.get("passed"), bool):
        regime_pass_signal = bool(regime_check.get("passed"))
    elif isinstance(iron_regime.get("passed"), bool):
        regime_pass_signal = bool(iron_regime.get("passed"))

    risk_pass_signal: bool | None = None
    if isinstance(position_size_check.get("passed"), bool):
        risk_pass_signal = bool(position_size_check.get("passed"))

    def _status(pass_signal: bool | None) -> str:
        if pass_signal is None:
            return "unknown"
        return "pass" if pass_signal else "blocked"

    gate_status = {
        "regime": {
            "status": _status(regime_pass_signal),
            "detail": str(
                regime_check.get("note") or iron_regime.get("regime") or "No regime evidence"
            ),
            "evidence_date": str(
                iron_condor_state.get("last_updated") or swarm_state.get("last_updated") or ""
            ),
        },
        "vix": {
            "status": _status(regime_pass_signal),
            "value": regime_check.get("vix"),
            "detail": str(regime_check.get("note") or "No VIX evidence"),
        },
        "dte": {
            "status": (
                "unknown"
                if dte_value is None
                else (
                    "pass"
                    if DEFAULT_MIN_TARGET_DTE <= dte_value <= DEFAULT_MAX_TARGET_DTE
                    else "blocked"
                )
            ),
            "value": dte_value,
            "target_range": f"{DEFAULT_MIN_TARGET_DTE}-{DEFAULT_MAX_TARGET_DTE}",
        },
        "risk_caps": {
            "status": _status(risk_pass_signal),
            "detail": (
                "position_size_check unavailable"
                if risk_pass_signal is None
                else (
                    f"requested={position_size_check.get('requested')} max={position_size_check.get('max_allowed')}"
                )
            ),
        },
        "liquidity": {
            "status": (
                "unknown"
                if not recent_decisions
                else (
                    "blocked"
                    if low_liquidity_events
                    >= max(1, len(volume_ratios) // 2 if volume_ratios else 1)
                    else "pass"
                )
            ),
            "avg_volume_ratio": avg_volume_ratio,
            "low_liquidity_events": low_liquidity_events,
            "threshold_min_volume_ratio": round(min_liquidity_volume_ratio, 4),
        },
    }

    ai_credit_stress_signal = _load_ai_credit_stress_signal(data_dir, state)
    ai_status = _normalize_ai_credit_stress_status(ai_credit_stress_signal)
    ai_reasons = ai_credit_stress_signal.get("reasons", [])
    ai_reason_text = ""
    if isinstance(ai_reasons, list) and ai_reasons:
        ai_reason_text = str(ai_reasons[0])
    if not ai_reason_text:
        ai_reason_text = str(ai_credit_stress_signal.get("note") or "No AI credit stress evidence")
    ai_score = ai_credit_stress_signal.get("severity_score")
    gate_status["ai_credit_stress"] = {
        "status": ai_status,
        "signal_status": str(ai_credit_stress_signal.get("status") or "unknown"),
        "severity_score": _as_float(ai_score, 0.0) if ai_score is not None else None,
        "signal_date": ai_credit_stress_signal.get("latest_data_date"),
        "source": ai_credit_stress_signal.get("source", "none"),
        "detail": ai_reason_text,
    }

    usd_macro_signal = _load_usd_macro_sentiment_signal(data_dir, state)
    usd_status = _normalize_usd_macro_status(usd_macro_signal)
    usd_score = usd_macro_signal.get("bearish_score")
    usd_multiplier = _as_float(usd_macro_signal.get("position_size_multiplier"), 0.0)
    if usd_multiplier <= 0:
        if usd_status == "blocked":
            usd_multiplier = DEFAULT_USD_MACRO_BLOCK_MULTIPLIER
        elif usd_status == "watch":
            usd_multiplier = DEFAULT_USD_MACRO_WATCH_MULTIPLIER
        else:
            usd_multiplier = 1.0
    usd_reasons = usd_macro_signal.get("reasons", [])
    usd_reason_text = ""
    if isinstance(usd_reasons, list) and usd_reasons:
        usd_reason_text = str(usd_reasons[0])
    if not usd_reason_text:
        usd_reason_text = str(usd_macro_signal.get("note") or "No USD macro sentiment evidence")
    gate_status["usd_macro"] = {
        "status": usd_status,
        "signal_status": str(usd_macro_signal.get("status") or "unknown"),
        "bearish_score": _as_float(usd_score, 0.0) if usd_score is not None else None,
        "position_size_multiplier": round(min(1.0, max(0.1, usd_multiplier)), 4),
        "signal_date": usd_macro_signal.get("latest_data_date"),
        "source": usd_macro_signal.get("source", "none"),
        "detail": usd_reason_text,
    }

    blocked_categories = [
        name for name, payload in gate_status.items() if payload.get("status") == "blocked"
    ]

    if closed_trades_recent > 0:
        summary = (
            "Closed trades exist in lookback window; no-trade root cause not currently active."
        )
    elif qualified_setups_recent == 0:
        summary = (
            "No qualified setups captured in lookback window. "
            "Focus on setup generation cadence before adjusting execution."
        )
    elif blocked_categories:
        summary = f"No closed trades detected; likely blocked by: {', '.join(blocked_categories)}."
    else:
        summary = (
            "No closed trades detected and no single blocking gate identified. "
            "Investigate strategy cadence and execution conversion."
        )

    top_reasons = [
        {"reason": reason, "count": count} for reason, count in reason_counter.most_common(5)
    ]
    gate_block_counts = {
        category: int(count) for category, count in sorted(category_counter.items())
    }

    return {
        "lookback_days": DEFAULT_LOOKBACK_DAYS,
        "decision_records_observed": len(recent_decisions),
        "closed_trades_observed": closed_trades_recent,
        "qualified_setups_observed": qualified_setups_recent,
        "gate_status": gate_status,
        "blocked_categories": blocked_categories,
        "gate_block_counts": gate_block_counts,
        "top_rejection_reasons": top_reasons,
        "summary": summary,
        "updated_at": datetime.now(timezone.utc).isoformat(),
    }


def _extract_recent_closed_trades(
    trades_payload: dict[str, Any],
    *,
    today: date,
    lookback_days: int = DEFAULT_LOOKBACK_DAYS,
) -> list[dict[str, Any]]:
    all_trades = trades_payload.get("trades", [])
    if not isinstance(all_trades, list):
        return []

    start_date = today - timedelta(days=max(1, lookback_days) - 1)
    rows: list[dict[str, Any]] = []
    for raw in all_trades:
        if not isinstance(raw, dict):
            continue
        if str(raw.get("status", "")).lower() != "closed":
            continue

        closed_at = _parse_date(
            raw.get("exit_date")
            or raw.get("exit_time")
            or raw.get("closed_at")
            or raw.get("timestamp")
        )
        if closed_at is None or closed_at < start_date or closed_at > today:
            continue

        pnl = _as_float(raw.get("realized_pnl", raw.get("pnl", raw.get("pl", 0.0))), 0.0)
        outcome = str(raw.get("outcome", "")).lower()
        if outcome not in {"win", "loss", "breakeven"}:
            if pnl > 0:
                outcome = "win"
            elif pnl < 0:
                outcome = "loss"
            else:
                outcome = "breakeven"

        rows.append({"closed_at": closed_at.isoformat(), "pnl": pnl, "outcome": outcome})
    return rows


def _sync_paper_win_rate_from_trades_payload(
    state: dict[str, Any], trades_payload: dict[str, Any]
) -> None:
    """Mirror ledger-derived win rate into system_state.paper_account."""
    stats = trades_payload.get("stats", {}) if isinstance(trades_payload, dict) else {}
    closed_trades = _as_int(stats.get("closed_trades"), 0)
    win_rate_raw = stats.get("win_rate_pct")
    win_rate_val = _as_float(win_rate_raw, 0.0) if win_rate_raw is not None else 0.0

    state.setdefault("paper_account", {})
    state["paper_account"]["win_rate"] = round(win_rate_val, 2)
    state["paper_account"]["win_rate_sample_size"] = closed_trades


def _compute_ic_win_rate_from_history(state: dict[str, Any]) -> dict[str, Any]:
    """Compute win rate from complete SPY iron condor round-trips in trade_history.

    Groups individual legs by expiry date (encoded in the symbol, e.g. "260313").
    An iron condor round-trip has >= 8 legs (4 open + 4 close). For each complete
    round-trip, net cash flow = sum(SELL prices) - sum(BUY prices). Positive = win.

    Expiry groups with still-open positions are excluded — only fully settled ICs count.
    """
    trade_history = state.get("trade_history", []) if isinstance(state, dict) else []
    if not isinstance(trade_history, list):
        trade_history = []

    # Identify expiry dates that still have open positions (not settled yet)
    open_expiries: set[str] = set()
    for pos in state.get("positions", []):
        if not isinstance(pos, dict):
            continue
        m = _SPY_OPTION_RE.match(str(pos.get("symbol", "")))
        if m:
            open_expiries.add(m.group(1))

    # Group legs by expiry date extracted from symbol
    expiry_groups: dict[str, list[dict[str, Any]]] = {}
    for t in trade_history:
        if not isinstance(t, dict):
            continue
        symbol = str(t.get("symbol", ""))
        m = _SPY_OPTION_RE.match(symbol)
        if not m:
            continue
        expiry_key = m.group(1)  # e.g. "260220"
        expiry_groups.setdefault(expiry_key, []).append(t)

    wins = 0
    losses = 0
    total_pnl = 0.0

    for expiry_key, legs in expiry_groups.items():
        # Skip if this expiry still has open positions (IC not fully settled)
        if expiry_key in open_expiries:
            continue

        # A complete IC round-trip needs >= 8 legs (4 open + 4 close).
        # Groups with fewer legs are partial — skip them.
        if len(legs) < 8:
            continue

        # Net cash flow: SELL = credit (+), BUY = debit (-)
        net = 0.0
        for leg in legs:
            # trade_history stores option premiums as per-share price strings.
            # Convert to dollars with contract multiplier (100) and quantity.
            price = _as_float(leg.get("price"), 0.0)
            qty = _as_float(leg.get("qty", leg.get("quantity", 1.0)), 1.0)
            cash = price * qty * 100.0

            side = str(leg.get("side", "")).upper()
            if "SELL" in side:
                net += cash
            elif "BUY" in side:
                net -= cash

        total_pnl += net
        if net > 0:
            wins += 1
        elif net < 0:
            losses += 1

    samples = wins + losses
    if samples == 0:
        return {
            "samples": 0,
            "wins": 0,
            "win_rate_pct": 0.0,
            "expectancy": 0.0,
            "evidence_source": "no_completed_ic_trades",
        }

    win_rate_pct = round((wins / samples) * 100.0, 2)
    expectancy = round(total_pnl / samples, 4)

    return {
        "samples": samples,
        "wins": wins,
        "win_rate_pct": win_rate_pct,
        "expectancy": expectancy,
        "evidence_source": "trade_history_ic_only",
    }


def compute_weekly_gate(
    state: dict[str, Any],
    *,
    trades_path: Path = DEFAULT_TRADES_PATH,
    weekly_history_path: Path = DEFAULT_WEEKLY_HISTORY_PATH,
    today: date | None = None,
) -> tuple[dict[str, Any], list[dict[str, Any]]]:
    """Compute weekly risk gate and persist week-over-week quality history."""
    today = today or date.today()
    trades_payload = _load_json_dict(trades_path)
    recent_closed = _extract_recent_closed_trades(trades_payload, today=today)
    data_dir = trades_path.parent
    min_liquidity_volume_ratio = _resolve_min_liquidity_volume_ratio(data_dir)
    recent_decisions = _extract_recent_session_decisions(
        data_dir=data_dir,
        today=today,
        lookback_days=DEFAULT_LOOKBACK_DAYS,
    )
    qualified_setups = sum(1 for row in recent_decisions if row.get("qualified") is True)

    samples = len(recent_closed)
    wins = sum(1 for row in recent_closed if row.get("outcome") == "win")
    total_pnl = sum(_as_float(row.get("pnl"), 0.0) for row in recent_closed)
    lifetime_closed_trades = _as_int(
        _safe_nested_dict(trades_payload, "stats").get("closed_trades"),
        0,
    )

    if samples > 0:
        win_rate_pct = round((wins / samples) * 100.0, 2)
        expectancy = round(total_pnl / samples, 4)
        evidence_source = "trades.json"
    else:
        # Fallback: compute IC-only win rate from trade_history in system_state.
        # The blended paper_account.win_rate includes non-IC trades (REITs, stocks,
        # individual puts) which pollute the iron condor strategy signal.
        ic_stats = _compute_ic_win_rate_from_history(state)
        samples = ic_stats["samples"]
        wins = ic_stats["wins"]
        win_rate_pct = ic_stats["win_rate_pct"]
        expectancy = ic_stats["expectancy"]
        evidence_source = ic_stats["evidence_source"]
        if lifetime_closed_trades <= 0:
            lifetime_closed_trades = samples

    mode = "validation"
    recommended_max = 0.02
    block_new_positions = False
    reason = "Insufficient recent weekly evidence; keep conservative sizing."

    if samples >= DEFAULT_WEEKLY_MIN_SAMPLES and expectancy <= 0:
        mode = "defensive"
        recommended_max = 0.01
        block_new_positions = True
        reason = (
            f"Weekly expectancy ${expectancy:.2f}/trade over {samples} samples is non-positive."
        )
    elif samples >= DEFAULT_WEEKLY_MIN_SAMPLES and win_rate_pct < 65.0:
        mode = "defensive"
        recommended_max = 0.01
        # Only block if BOTH win rate is poor AND expectancy is non-positive.
        # A strategy with positive expectancy is net profitable even with
        # sub-55% win rate (common for iron condors with favorable risk/reward).
        block_new_positions = win_rate_pct < 55.0 and samples >= 8 and expectancy <= 0
        reason = f"Weekly win rate {win_rate_pct:.1f}% is below 65% safety threshold."
    elif samples >= 12 and win_rate_pct >= 80.0 and expectancy > 0:
        mode = "expansion_candidate"
        recommended_max = 0.03
        reason = "Weekly edge is healthy; candidate for gradual scaling."
    elif samples >= DEFAULT_WEEKLY_MIN_SAMPLES:
        mode = "cautious"
        recommended_max = 0.015
        reason = "Weekly edge mixed; stay cautious while collecting more evidence."

    cadence_kpi = {
        "enabled": True,
        "min_qualified_setups_per_week": DEFAULT_MIN_QUALIFIED_SETUPS_PER_WEEK,
        "min_closed_trades_per_week": DEFAULT_MIN_CLOSED_TRADES_PER_WEEK,
        "qualified_setups_observed": qualified_setups,
        "closed_trades_observed": samples,
        "meets_qualified_setups": qualified_setups >= DEFAULT_MIN_QUALIFIED_SETUPS_PER_WEEK,
        "meets_closed_trades": samples >= DEFAULT_MIN_CLOSED_TRADES_PER_WEEK,
    }
    cadence_kpi["passed"] = bool(
        cadence_kpi["meets_qualified_setups"] and cadence_kpi["meets_closed_trades"]
    )
    if cadence_kpi["passed"]:
        cadence_kpi["alert_level"] = "ok"
        cadence_kpi["summary"] = "Cadence KPI met."
    elif not cadence_kpi["meets_qualified_setups"] and not cadence_kpi["meets_closed_trades"]:
        cadence_kpi["alert_level"] = "critical"
        cadence_kpi["summary"] = (
            "Cadence KPI miss: qualified setups and closed trades are both below weekly minimum."
        )
    else:
        cadence_kpi["alert_level"] = "warning"
        cadence_kpi["summary"] = "Cadence KPI miss: one or more weekly minimums not met."

    no_trade_diagnostic = _compute_no_trade_diagnostic(
        data_dir=data_dir,
        state=state,
        recent_decisions=recent_decisions,
        closed_trades_recent=samples,
        qualified_setups_recent=qualified_setups,
        min_liquidity_volume_ratio=min_liquidity_volume_ratio,
    )

    ai_credit_gate = _safe_nested_dict(no_trade_diagnostic, "gate_status", "ai_credit_stress")
    ai_credit_status = str(ai_credit_gate.get("status") or "unknown").lower()
    ai_credit_score = _as_float(ai_credit_gate.get("severity_score"), 0.0)
    if ai_credit_status == "blocked":
        mode = "defensive"
        recommended_max = min(recommended_max, 0.01)
        block_new_positions = (
            block_new_positions or ai_credit_score >= DEFAULT_AI_CREDIT_HARD_BLOCK_SCORE
        )
        reason = f"{reason} AI credit stress blocked: score={ai_credit_score:.1f}."
    elif ai_credit_status == "watch":
        if mode == "expansion_candidate":
            mode = "cautious"
        recommended_max = min(recommended_max, 0.015)
        reason = f"{reason} AI credit stress elevated; hold cautious sizing."

    usd_macro_gate = _safe_nested_dict(no_trade_diagnostic, "gate_status", "usd_macro")
    usd_macro_status = str(usd_macro_gate.get("status") or "unknown").lower()
    usd_macro_multiplier = _as_float(usd_macro_gate.get("position_size_multiplier"), 1.0)
    if usd_macro_multiplier <= 0:
        usd_macro_multiplier = 1.0
    usd_macro_multiplier = min(1.0, max(0.1, usd_macro_multiplier))
    if usd_macro_status in {"watch", "blocked"} and usd_macro_multiplier < 1.0:
        adjusted_limit = round(recommended_max * usd_macro_multiplier, 4)
        recommended_max = min(recommended_max, adjusted_limit)
        if mode == "expansion_candidate":
            mode = "cautious"
        score_text = usd_macro_gate.get("bearish_score")
        score_suffix = (
            f" score={_as_float(score_text, 0.0):.1f}"
            if isinstance(score_text, (int, float))
            else ""
        )
        reason = (
            f"{reason} USD macro sentiment {usd_macro_status}; "
            f"applied size multiplier {usd_macro_multiplier:.2f}.{score_suffix}"
        )

    weekly_history = _load_json_list(weekly_history_path)
    week_start = today - timedelta(days=today.weekday())
    week_start_iso = week_start.isoformat()
    weekly_entry_fields = {
        "week_start": week_start_iso,
        "sample_size": samples,
        "win_rate_pct": win_rate_pct,
        "expectancy_per_trade": expectancy,
        "mode": mode,
        "qualified_setups": qualified_setups,
        "cadence_passed": cadence_kpi["passed"],
    }

    replaced = False
    for idx, row in enumerate(weekly_history):
        if str(row.get("week_start")) == week_start_iso:
            unchanged = (
                _as_int(row.get("sample_size"), -1) == samples
                and _as_float(row.get("win_rate_pct"), -1.0) == win_rate_pct
                and _as_float(row.get("expectancy_per_trade"), -999999.0) == expectancy
                and str(row.get("mode", "")) == mode
                and _as_int(row.get("qualified_setups"), -1) == qualified_setups
                and bool(row.get("cadence_passed")) is cadence_kpi["passed"]
            )
            if unchanged:
                # Keep historical timestamp untouched when nothing changed.
                weekly_entry = row
            else:
                weekly_entry = {
                    **weekly_entry_fields,
                    "updated_at": datetime.now(timezone.utc).isoformat(),
                }
            weekly_history[idx] = weekly_entry
            replaced = True
            break
    if not replaced:
        weekly_history.append(
            {
                **weekly_entry_fields,
                "updated_at": datetime.now(timezone.utc).isoformat(),
            }
        )

    weekly_history.sort(key=lambda row: str(row.get("week_start", "")))
    weekly_history = weekly_history[-DEFAULT_HISTORY_WEEKS:]

    positive_streak = 0
    for row in reversed(weekly_history):
        s = _as_int(row.get("sample_size"), 0)
        wr = _as_float(row.get("win_rate_pct"), 0.0)
        ex = _as_float(row.get("expectancy_per_trade"), 0.0)
        if s >= DEFAULT_WEEKLY_MIN_SAMPLES and wr >= 75.0 and ex > 0:
            positive_streak += 1
            continue
        break

    if mode == "expansion_candidate" and positive_streak < 2:
        recommended_max = min(recommended_max, 0.02)
        reason = (
            f"Weekly edge improved but only {positive_streak} qualifying positive week(s); "
            "require >=2 before scaling."
        )

    scaling_sample_gate = {
        "enabled": True,
        "min_closed_trades_for_scaling": DEFAULT_MIN_CLOSED_TRADES_FOR_SCALING,
        "closed_trades_observed": lifetime_closed_trades,
        "passed": lifetime_closed_trades >= DEFAULT_MIN_CLOSED_TRADES_FOR_SCALING,
    }

    if mode == "expansion_candidate" and not scaling_sample_gate["passed"]:
        mode = "cautious"
        recommended_max = min(recommended_max, 0.02)
        reason = (
            f"Scaling blocked: {lifetime_closed_trades} closed trades < "
            f"{DEFAULT_MIN_CLOSED_TRADES_FOR_SCALING} minimum for statistically valid scaling."
        )

    if not cadence_kpi["passed"]:
        recommended_max = min(recommended_max, 0.015)
        if mode == "expansion_candidate":
            mode = "cautious"
        reason = (
            f"{reason} Cadence KPI miss: setups {qualified_setups}/"
            f"{DEFAULT_MIN_QUALIFIED_SETUPS_PER_WEEK}, closed trades {samples}/"
            f"{DEFAULT_MIN_CLOSED_TRADES_PER_WEEK}."
        )

    weekly_history_path.parent.mkdir(parents=True, exist_ok=True)
    new_weekly_payload = json.dumps(weekly_history, indent=2) + "\n"
    current_weekly_payload = (
        weekly_history_path.read_text(encoding="utf-8") if weekly_history_path.exists() else ""
    )
    if current_weekly_payload != new_weekly_payload:
        weekly_history_path.write_text(new_weekly_payload, encoding="utf-8")

    gate = {
        "enabled": True,
        "lookback_days": DEFAULT_LOOKBACK_DAYS,
        "mode": mode,
        "sample_size": samples,
        "win_rate_pct": win_rate_pct,
        "expectancy_per_trade": expectancy,
        "recommended_max_position_pct": round(recommended_max, 4),
        "block_new_positions": block_new_positions,
        "reason": reason,
        "positive_weeks_streak": positive_streak,
        "evidence_source": evidence_source,
        "cadence_kpi": cadence_kpi,
        "scale_blocked_by_cadence": not cadence_kpi["passed"],
        "ai_credit_stress": ai_credit_gate,
        "scale_blocked_by_ai_credit_stress": ai_credit_status == "blocked",
        "usd_macro_sentiment": usd_macro_gate,
        "scale_multiplier_from_usd_macro": round(usd_macro_multiplier, 4),
        "scaling_sample_gate": scaling_sample_gate,
        "liquidity_min_volume_ratio": round(min_liquidity_volume_ratio, 4),
        "no_trade_diagnostic": no_trade_diagnostic,
        "updated_at": datetime.now(timezone.utc).isoformat(),
    }
    return gate, weekly_history


def compute_contribution_plan(
    state: dict[str, Any],
    *,
    today: date | None = None,
) -> dict[str, Any]:
    """Compute ASAP monthly-income progress tracking for North Star."""
    today = today or date.today()
    paper = state.get("paper_account", {}) if isinstance(state, dict) else {}
    live = state.get("live_account", {}) if isinstance(state, dict) else {}
    existing = state.get("north_star_contributions", {}) if isinstance(state, dict) else {}

    current_equity = _as_float(
        paper.get("equity"),
        _as_float(state.get("account", {}).get("current_equity"), 0.0),
    )

    month_key = today.strftime("%Y-%m")
    existing_month = str(existing.get("month", ""))
    if existing_month == month_key:
        month_start_equity = _as_float(existing.get("month_start_equity"), current_equity)
        live_month_start_equity = _as_float(
            existing.get("live_month_start_equity"),
            _as_float(live.get("equity"), 0.0),
        )
    else:
        month_start_equity = current_equity
        live_month_start_equity = _as_float(live.get("equity"), 0.0)

    equity_change_this_month = round(current_equity - month_start_equity, 2)
    live_current_equity = _as_float(live.get("equity"), 0.0)
    live_change_this_month = round(live_current_equity - live_month_start_equity, 2)
    live_positions = _as_int(live.get("positions_count"), 0)

    estimated_live_contribution = None
    contribution_confidence = "low"
    inference_note = (
        "Cannot separate deposits from trading P/L in broker snapshots; "
        "using equity deltas as directional signal only."
    )
    if live_positions == 0:
        estimated_live_contribution = round(max(0.0, live_change_this_month), 2)
        contribution_confidence = "medium"
        inference_note = "Live account has no open positions; live equity change is treated as estimated contribution."

    monthly_target = max(0.0, float(NORTH_STAR_MONTHLY_AFTER_TAX))
    daily_target = max(0.0, float(NORTH_STAR_DAILY_AFTER_TAX))
    progress_pct = (
        (equity_change_this_month / monthly_target * 100.0) if monthly_target > 0 else 0.0
    )
    remaining_to_monthly_target = max(0.0, monthly_target - equity_change_this_month)
    days_in_month = calendar.monthrange(today.year, today.month)[1]
    days_elapsed = max(1, today.day)
    days_remaining = max(0, days_in_month - today.day)
    projected_month_end_pnl = round((equity_change_this_month / days_elapsed) * days_in_month, 2)
    projected_gap_at_month_end = round(max(0.0, monthly_target - projected_month_end_pnl), 2)
    required_daily_from_now = (
        round(remaining_to_monthly_target / days_remaining, 2) if days_remaining > 0 else 0.0
    )

    return {
        "enabled": True,
        "target_mode": "asap_monthly_income",
        "month": month_key,
        "target_date": None,
        "months_remaining": None,
        "target_capital": NORTH_STAR_TARGET_CAPITAL,
        "monthly_after_tax_target": round(monthly_target, 2),
        "daily_after_tax_target": round(daily_target, 2),
        "current_equity": round(current_equity, 2),
        "required_cagr_without_contributions": None,
        "required_monthly_contribution_by_return": {},
        "assumed_return": None,
        "required_monthly_contribution_at_assumed_return": None,
        "month_start_equity": round(month_start_equity, 2),
        "equity_change_this_month": equity_change_this_month,
        "monthly_target_progress_pct": round(max(0.0, progress_pct), 2),
        "remaining_to_monthly_target": round(remaining_to_monthly_target, 2),
        "days_elapsed_this_month": days_elapsed,
        "days_remaining_this_month": days_remaining,
        "required_daily_after_tax_from_now": required_daily_from_now,
        "projected_month_end_after_tax_pnl": projected_month_end_pnl,
        "projected_gap_to_monthly_target": projected_gap_at_month_end,
        "live_month_start_equity": round(live_month_start_equity, 2),
        "live_equity_change_this_month": live_change_this_month,
        "estimated_live_contribution_this_month": estimated_live_contribution,
        "contribution_estimate_confidence": contribution_confidence,
        "inference_note": inference_note,
        "updated_at": datetime.now(timezone.utc).isoformat(),
    }


def apply_operating_plan_to_state(
    state: dict[str, Any],
    *,
    trades_path: Path = DEFAULT_TRADES_PATH,
    weekly_history_path: Path = DEFAULT_WEEKLY_HISTORY_PATH,
    today: date | None = None,
) -> tuple[dict[str, Any], list[dict[str, Any]]]:
    """Apply weekly gate + contribution plan to mutable system_state payload."""
    today = today or date.today()
    trades_payload = _load_json_dict(trades_path)
    _sync_paper_win_rate_from_trades_payload(state, trades_payload)

    weekly_gate, weekly_history = compute_weekly_gate(
        state,
        trades_path=trades_path,
        weekly_history_path=weekly_history_path,
        today=today,
    )
    contributions = compute_contribution_plan(state, today=today)

    state["north_star_weekly_gate"] = weekly_gate
    state["north_star_contributions"] = contributions

    state.setdefault("risk", {})
    state["risk"]["weekly_gate_mode"] = weekly_gate.get("mode")
    state["risk"]["weekly_gate_recommended_max_position_pct"] = weekly_gate.get(
        "recommended_max_position_pct"
    )
    state["risk"]["weekly_cadence_kpi_passed"] = bool(
        _safe_nested_dict(weekly_gate, "cadence_kpi").get("passed")
    )
    state["risk"]["weekly_scaling_sample_gate_passed"] = bool(
        _safe_nested_dict(weekly_gate, "scaling_sample_gate").get("passed")
    )
    state["risk"]["weekly_ai_credit_stress_status"] = str(
        _safe_nested_dict(weekly_gate, "ai_credit_stress").get("status") or "unknown"
    )
    state["risk"]["weekly_ai_credit_stress_score"] = _safe_nested_dict(
        weekly_gate, "ai_credit_stress"
    ).get("severity_score")
    state["risk"]["weekly_usd_macro_status"] = str(
        _safe_nested_dict(weekly_gate, "usd_macro_sentiment").get("status") or "unknown"
    )
    state["risk"]["weekly_usd_macro_score"] = _safe_nested_dict(
        weekly_gate, "usd_macro_sentiment"
    ).get("bearish_score")
    state["risk"]["weekly_usd_macro_multiplier"] = _safe_nested_dict(
        weekly_gate, "usd_macro_sentiment"
    ).get("position_size_multiplier")
    return state, weekly_history

"""Milestone controller for strategy-family gating and North Star probability.

This module enforces a simple policy:
- Auto-pause strategy families when rolling win-rate/expectancy are below thresholds.
- Keep only the primary family in validation mode when samples are insufficient.
- Publish a daily North Star probability score from current edge + capital trajectory.
"""

from __future__ import annotations

import json
import os
from datetime import datetime
from pathlib import Path
from typing import Any

try:
    from src.core.trading_constants import (
        NORTH_STAR_MONTHLY_AFTER_TAX,
        NORTH_STAR_TARGET_CAPITAL,
        NORTH_STAR_TARGET_WIN_RATE_PCT,
    )
except Exception:
    NORTH_STAR_MONTHLY_AFTER_TAX = 6_000.0
    NORTH_STAR_TARGET_CAPITAL = 300_000.0
    NORTH_STAR_TARGET_WIN_RATE_PCT = 80.0

DEFAULT_STATE_PATH = Path("data/system_state.json")
DEFAULT_TRADES_PATH = Path("data/trades.json")
DEFAULT_TARGET_MODE = "asap_monthly_income"
DEFAULT_MONTHLY_AFTER_TAX_TARGET = NORTH_STAR_MONTHLY_AFTER_TAX
DEFAULT_TARGET_CAPITAL = NORTH_STAR_TARGET_CAPITAL
DEFAULT_TARGET_WIN_RATE_PCT = NORTH_STAR_TARGET_WIN_RATE_PCT
DEFAULT_ROLLING_WINDOW = int(os.getenv("MILESTONE_ROLLING_WINDOW", "50"))
DEFAULT_PRIMARY_FAMILY = os.getenv("PRIMARY_STRATEGY_FAMILY", "options_income")

KNOWN_FAMILIES = ("options_income", "equity_momentum", "alternatives", "other")
FAMILY_THRESHOLDS: dict[str, dict[str, float | int]] = {
    # Lowered from 75% to 60% for validation phase (Feb 13, 2026).
    # Rationale: 75% threshold with contaminated win rate (37.5% from non-IC trades)
    # was permanently blocking all IC entries, preventing the system from building
    # the 30-trade track record needed for North Star validation.
    # Once 30+ IC trades are closed, raise back to 75%.
    "options_income": {"min_win_rate_pct": 60.0, "min_expectancy": 0.0, "min_samples": 8},
    "equity_momentum": {"min_win_rate_pct": 55.0, "min_expectancy": 0.0, "min_samples": 12},
    "alternatives": {"min_win_rate_pct": 55.0, "min_expectancy": 0.0, "min_samples": 12},
    "other": {"min_win_rate_pct": 55.0, "min_expectancy": 0.0, "min_samples": 12},
}


def _as_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(value)
    except (TypeError, ValueError):
        return default


def _as_int(value: Any, default: int = 0) -> int:
    try:
        return int(value)
    except (TypeError, ValueError):
        return default


def _load_json_dict(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    try:
        with path.open("r", encoding="utf-8") as handle:
            data = json.load(handle)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def resolve_strategy_family(strategy: str) -> str:
    """Map a strategy label to a coarse family for gating."""
    text = (strategy or "").strip().lower()
    if not text:
        return "other"

    options_tokens = (
        "iron_condor",
        "credit_spread",
        "put_spread",
        "call_spread",
        "vertical_spread",
        "csp",
        "covered_call",
        "option",
    )
    momentum_tokens = ("momentum", "trend", "swing", "dca", "core_strategy")
    alt_tokens = ("reit", "metals", "precious", "income")

    if any(token in text for token in options_tokens):
        return "options_income"
    if any(token in text for token in momentum_tokens):
        return "equity_momentum"
    if any(token in text for token in alt_tokens):
        return "alternatives"
    return "other"


def _extract_closed_trades(
    trades_data: dict[str, Any], rolling_window: int
) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    trades = trades_data.get("trades", [])
    if not isinstance(trades, list):
        return rows

    for raw in trades:
        if not isinstance(raw, dict):
            continue
        status = str(raw.get("status", "")).lower()
        if status != "closed":
            continue

        strategy = str(raw.get("strategy") or raw.get("strategy_name") or "")
        symbol = str(raw.get("symbol") or "")
        family = resolve_strategy_family(strategy or symbol)
        pnl = _as_float(raw.get("realized_pnl", raw.get("pnl", raw.get("pl", 0.0))), 0.0)

        outcome = str(raw.get("outcome", "")).lower()
        if outcome not in {"win", "loss", "breakeven"}:
            if pnl > 0:
                outcome = "win"
            elif pnl < 0:
                outcome = "loss"
            else:
                outcome = "breakeven"

        closed_at = str(
            raw.get("exit_date")
            or raw.get("exit_time")
            or raw.get("closed_at")
            or raw.get("timestamp")
            or ""
        )
        rows.append(
            {
                "family": family,
                "strategy": strategy,
                "symbol": symbol,
                "pnl": pnl,
                "outcome": outcome,
                "closed_at": closed_at,
            }
        )

    rows.sort(key=lambda item: item.get("closed_at", ""))
    if rolling_window > 0:
        rows = rows[-rolling_window:]
    return rows


def _metrics_for_family(
    family: str,
    closed_trades: list[dict[str, Any]],
    state: dict[str, Any],
) -> dict[str, Any]:
    family_rows = [row for row in closed_trades if row.get("family") == family]
    samples = len(family_rows)
    wins = sum(1 for row in family_rows if row.get("outcome") == "win")
    losses = sum(1 for row in family_rows if row.get("outcome") == "loss")
    total_pnl = sum(_as_float(row.get("pnl"), 0.0) for row in family_rows)

    metrics: dict[str, Any] = {
        "samples": samples,
        "wins": wins,
        "losses": losses,
        "total_pnl": round(total_pnl, 2),
        "win_rate_pct": round((wins / samples) * 100.0, 2) if samples > 0 else None,
        "expectancy": round(total_pnl / samples, 4) if samples > 0 else None,
        "evidence_source": "trades.json" if samples > 0 else "none",
    }

    # Fallback: use paper_account summary for primary family if paired-trade ledger is sparse.
    if samples == 0 and family == DEFAULT_PRIMARY_FAMILY:
        paper = state.get("paper_account", {}) if isinstance(state, dict) else {}
        paper_samples = _as_int(paper.get("win_rate_sample_size"), 0)
        paper_win_rate = _as_float(paper.get("win_rate"), 0.0)
        paper_total_pl = _as_float(paper.get("total_pl"), 0.0)
        if paper_samples > 0:
            expectancy_estimate = round(paper_total_pl / paper_samples, 4)
            metrics.update(
                {
                    "samples": paper_samples,
                    "wins": round((paper_win_rate / 100.0) * paper_samples),
                    "losses": max(
                        0, paper_samples - round((paper_win_rate / 100.0) * paper_samples)
                    ),
                    "win_rate_pct": round(paper_win_rate, 2),
                    "expectancy": expectancy_estimate,
                    "evidence_source": "paper_account_estimate",
                }
            )

    return metrics


def _thresholds_for_family(family: str) -> dict[str, float | int]:
    base = FAMILY_THRESHOLDS.get(family, FAMILY_THRESHOLDS["other"]).copy()
    return {
        "min_win_rate_pct": _as_float(base.get("min_win_rate_pct"), 55.0),
        "min_expectancy": _as_float(base.get("min_expectancy"), 0.0),
        "min_samples": _as_int(base.get("min_samples"), 12),
    }


def _evaluate_family_status(family: str, metrics: dict[str, Any]) -> dict[str, Any]:
    thresholds = _thresholds_for_family(family)
    samples = _as_int(metrics.get("samples"), 0)
    win_rate = metrics.get("win_rate_pct")
    expectancy = metrics.get("expectancy")
    min_samples = _as_int(thresholds.get("min_samples"), 12)
    min_win_rate = _as_float(thresholds.get("min_win_rate_pct"), 55.0)
    min_expectancy = _as_float(thresholds.get("min_expectancy"), 0.0)

    if samples < min_samples:
        paused = family != DEFAULT_PRIMARY_FAMILY
        status = "paused" if paused else "validation"
        reason = (
            f"{family} paused until {min_samples} closed trades (have {samples})."
            if paused
            else f"{family} validation mode ({samples}/{min_samples} closed trades)."
        )
        return {"status": status, "paused": paused, "reason": reason, "thresholds": thresholds}

    if win_rate is None or _as_float(win_rate) < min_win_rate:
        value = "N/A" if win_rate is None else f"{_as_float(win_rate):.1f}%"
        reason = f"{family} paused: win rate {value} below {min_win_rate:.1f}% threshold."
        return {"status": "paused", "paused": True, "reason": reason, "thresholds": thresholds}

    if expectancy is None:
        reason = f"{family} paused: expectancy unavailable with {samples} closed trades."
        return {"status": "paused", "paused": True, "reason": reason, "thresholds": thresholds}

    expectancy_val = _as_float(expectancy, 0.0)
    if expectancy_val <= min_expectancy:
        reason = (
            f"{family} paused: expectancy ${expectancy_val:.2f}/trade "
            f"<= ${min_expectancy:.2f} threshold."
        )
        return {"status": "paused", "paused": True, "reason": reason, "thresholds": thresholds}

    return {
        "status": "active",
        "paused": False,
        "reason": (
            f"{family} active: rolling win rate {float(win_rate):.1f}% and "
            f"expectancy ${expectancy_val:.2f}/trade meet thresholds."
        ),
        "thresholds": thresholds,
    }


def _estimate_annual_edge_from_expectancy(
    expectancy: float | None,
    samples: int,
    paper_day: int,
    equity: float,
) -> float:
    if expectancy is None or samples <= 0 or paper_day <= 0 or equity <= 0:
        return 0.0
    trades_per_day = samples / max(1, paper_day)
    expected_daily_pnl = float(expectancy) * trades_per_day
    return (expected_daily_pnl * 252.0) / equity


def _estimate_monthly_after_tax_from_expectancy(
    expectancy: float | None,
    samples: int,
    paper_day: int,
) -> float:
    if expectancy is None or samples <= 0 or paper_day <= 0:
        return 0.0
    trades_per_day = samples / max(1, paper_day)
    expected_daily_pnl = float(expectancy) * trades_per_day
    return max(0.0, expected_daily_pnl * 21.0)


def _north_star_probability(
    state: dict[str, Any],
    primary_metrics: dict[str, Any],
    primary_status: dict[str, Any],
) -> dict[str, Any]:
    paper = state.get("paper_account", {}) if isinstance(state, dict) else {}
    portfolio = state.get("portfolio", {}) if isinstance(state, dict) else {}
    paper_trading = state.get("paper_trading", {}) if isinstance(state, dict) else {}

    equity = _as_float(paper.get("equity"), 0.0)
    if equity <= 0:
        equity = _as_float(portfolio.get("equity"), 0.0)

    paper_day = _as_int(paper_trading.get("current_day"), 0)
    win_rate = primary_metrics.get("win_rate_pct")
    expectancy = primary_metrics.get("expectancy")
    samples = _as_int(primary_metrics.get("samples"), 0)
    weekly_gate = state.get("north_star_weekly_gate", {}) if isinstance(state, dict) else {}
    cadence_kpi = weekly_gate.get("cadence_kpi") if isinstance(weekly_gate, dict) else {}
    cadence_passed = bool(cadence_kpi.get("passed")) if isinstance(cadence_kpi, dict) else False
    cadence_setups = (
        _as_int(cadence_kpi.get("qualified_setups_observed"), 0)
        if isinstance(cadence_kpi, dict)
        else 0
    )

    estimated_cagr = _estimate_annual_edge_from_expectancy(expectancy, samples, paper_day, equity)
    estimated_monthly_after_tax = _estimate_monthly_after_tax_from_expectancy(
        expectancy, samples, paper_day
    )
    monthly_progress_ratio = (
        estimated_monthly_after_tax / DEFAULT_MONTHLY_AFTER_TAX_TARGET
        if DEFAULT_MONTHLY_AFTER_TAX_TARGET > 0
        else 0.0
    )
    trajectory_score = max(0.0, min(100.0, monthly_progress_ratio * 100.0))

    if win_rate is None:
        win_score = 25.0
    else:
        win_score = max(
            0.0, min(100.0, (_as_float(win_rate) / DEFAULT_TARGET_WIN_RATE_PCT) * 100.0)
        )

    expectancy_val = _as_float(expectancy, 0.0) if expectancy is not None else None
    if expectancy_val is None:
        edge_score = 20.0
    elif expectancy_val <= 0:
        edge_score = 0.0
    else:
        edge_score = max(0.0, min(100.0, (expectancy_val / 50.0) * 100.0))

    if cadence_passed:
        cadence_score = 100.0
    elif cadence_setups > 0:
        cadence_score = 45.0
    else:
        cadence_score = 15.0

    score = round(
        (0.4 * trajectory_score) + (0.25 * win_score) + (0.2 * edge_score) + (0.15 * cadence_score),
        1,
    )

    # Hard cap probability when primary strategy family is explicitly paused.
    if primary_status.get("paused"):
        score = min(score, 35.0)

    if score >= 75:
        label = "high"
    elif score >= 55:
        label = "medium"
    elif score >= 35:
        label = "low"
    else:
        label = "critical"

    return {
        "score": score,
        "label": label,
        "target_mode": DEFAULT_TARGET_MODE,
        "monthly_after_tax_target": round(DEFAULT_MONTHLY_AFTER_TAX_TARGET, 2),
        "estimated_monthly_after_tax_from_expectancy": round(estimated_monthly_after_tax, 2),
        "monthly_target_progress_pct": round(max(0.0, monthly_progress_ratio * 100.0), 2),
        "required_cagr": None,
        "estimated_cagr_from_expectancy": round(estimated_cagr, 4),
        "win_rate_pct": round(_as_float(win_rate, 0.0), 2) if win_rate is not None else None,
        "expectancy_per_trade": round(_as_float(expectancy, 0.0), 4)
        if expectancy is not None
        else None,
        "samples": samples,
        "target_capital": DEFAULT_TARGET_CAPITAL,
        "target_date": None,
    }


def compute_milestone_snapshot(
    state: dict[str, Any] | None = None,
    *,
    state_path: Path = DEFAULT_STATE_PATH,
    trades_path: Path = DEFAULT_TRADES_PATH,
) -> dict[str, Any]:
    """Compute full milestone status and North Star probability snapshot."""
    loaded_state = state if isinstance(state, dict) else _load_json_dict(state_path)
    trades_data = _load_json_dict(trades_path)
    closed = _extract_closed_trades(trades_data, rolling_window=DEFAULT_ROLLING_WINDOW)

    families: dict[str, Any] = {}
    paused: list[str] = []

    for family in KNOWN_FAMILIES:
        metrics = _metrics_for_family(family, closed, loaded_state)
        status = _evaluate_family_status(family, metrics)
        family_state = {
            "status": status["status"],
            "paused": status["paused"],
            "reason": status["reason"],
            "thresholds": status["thresholds"],
            "metrics": metrics,
        }
        families[family] = family_state
        if family_state["paused"]:
            paused.append(family)

    primary = (
        DEFAULT_PRIMARY_FAMILY if DEFAULT_PRIMARY_FAMILY in KNOWN_FAMILIES else "options_income"
    )
    primary_state = families.get(primary, families["options_income"])
    north_star = _north_star_probability(
        loaded_state,
        primary_state.get("metrics", {}),
        primary_state,
    )

    return {
        "enabled": True,
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "primary_family": primary,
        "rolling_window": DEFAULT_ROLLING_WINDOW,
        "strategy_families": families,
        "paused_families": paused,
        "north_star_probability": north_star,
    }


def get_milestone_context(
    strategy: str,
    *,
    state_path: Path = DEFAULT_STATE_PATH,
    trades_path: Path = DEFAULT_TRADES_PATH,
) -> dict[str, Any]:
    """Return gate-ready context for a specific strategy."""
    snapshot = compute_milestone_snapshot(state_path=state_path, trades_path=trades_path)
    family = resolve_strategy_family(strategy)
    family_state = snapshot.get("strategy_families", {}).get(family, {})
    paused = bool(family_state.get("paused"))

    block_reason = ""
    if paused:
        reason = str(family_state.get("reason") or "").strip()
        block_reason = (
            f"Milestone controller blocked '{family}' family: {reason}"
            if reason
            else f"Milestone controller blocked '{family}' family."
        )

    return {
        "enabled": True,
        "strategy_family": family,
        "family_status": family_state.get("status", "unknown"),
        "pause_buy_for_family": paused,
        "paused_families": snapshot.get("paused_families", []),
        "family_metrics": family_state.get("metrics", {}),
        "family_thresholds": family_state.get("thresholds", {}),
        "block_reason": block_reason,
        "north_star_probability_score": snapshot.get("north_star_probability", {}).get("score"),
    }


def apply_snapshot_to_state(state: dict[str, Any], snapshot: dict[str, Any]) -> dict[str, Any]:
    """Write milestone snapshot fields into mutable system_state payload."""
    state["strategy_milestones"] = {
        "enabled": snapshot.get("enabled", True),
        "generated_at": snapshot.get("generated_at"),
        "primary_family": snapshot.get("primary_family"),
        "rolling_window": snapshot.get("rolling_window"),
        "paused_families": snapshot.get("paused_families", []),
        "strategy_families": snapshot.get("strategy_families", {}),
    }

    north_star = state.setdefault("north_star", {})
    probability = snapshot.get("north_star_probability", {})
    north_star["probability_score"] = probability.get("score")
    north_star["probability_label"] = probability.get("label")
    north_star["target_mode"] = probability.get("target_mode")
    north_star["monthly_after_tax_target"] = probability.get("monthly_after_tax_target")
    north_star["estimated_monthly_after_tax_from_expectancy"] = probability.get(
        "estimated_monthly_after_tax_from_expectancy"
    )
    north_star["monthly_target_progress_pct"] = probability.get("monthly_target_progress_pct")
    north_star["required_cagr"] = probability.get("required_cagr")
    north_star["estimated_cagr_from_expectancy"] = probability.get("estimated_cagr_from_expectancy")
    north_star["target_capital"] = probability.get("target_capital")
    north_star["target_date"] = probability.get("target_date")
    north_star["updated_at"] = snapshot.get("generated_at")
    return state

"""North Star risk guard for trade sizing and risk-on gating.

This module converts live paper metrics in ``data/system_state.json`` into
runtime constraints that the mandatory trade gate can enforce.

Intent:
- Keep validation mode conservative until paper evidence is strong.
- Block new risk when observed performance is materially below target.
- Allow manual override when operator explicitly opts in.
"""

from __future__ import annotations

import os
from datetime import date, datetime
from pathlib import Path
from typing import Any

try:
    from src.core.trading_constants import (
        NORTH_STAR_MONTHLY_AFTER_TAX,
        NORTH_STAR_PAPER_VALIDATION_DAYS,
        NORTH_STAR_TARGET_CAPITAL,
        NORTH_STAR_TARGET_WIN_RATE_PCT,
    )
except Exception:
    NORTH_STAR_MONTHLY_AFTER_TAX = 6_000.0
    NORTH_STAR_TARGET_CAPITAL = 300_000.0
    NORTH_STAR_TARGET_WIN_RATE_PCT = 80.0
    NORTH_STAR_PAPER_VALIDATION_DAYS = 90

DEFAULT_STATE_PATH = Path("data/system_state.json")
DEFAULT_TARGET_MODE = "asap_monthly_income"
DEFAULT_MONTHLY_AFTER_TAX_TARGET = NORTH_STAR_MONTHLY_AFTER_TAX
DEFAULT_TARGET_CAPITAL = NORTH_STAR_TARGET_CAPITAL
DEFAULT_TARGET_WIN_RATE = NORTH_STAR_TARGET_WIN_RATE_PCT
DEFAULT_MIN_SAMPLE_SIZE = 30
DEFAULT_PAPER_DAYS = NORTH_STAR_PAPER_VALIDATION_DAYS


def _truthy(value: str) -> bool:
    return value.strip().lower() in {"1", "true", "yes", "on"}


def _as_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(value)
    except (TypeError, ValueError):
        return default


def _as_int(value: Any, default: int = 0) -> int:
    try:
        return int(value)
    except (TypeError, ValueError):
        return default


def _load_state(path: Path = DEFAULT_STATE_PATH) -> dict[str, Any]:
    if not path.exists():
        return {}
    try:
        import json

        with path.open("r", encoding="utf-8") as handle:
            data = json.load(handle)
            return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def _resolve_current_day(paper_trading: dict[str, Any]) -> int:
    explicit = _as_int(paper_trading.get("current_day"), 0)
    if explicit > 0:
        return explicit

    start_raw = paper_trading.get("start_date")
    if not start_raw:
        return 0

    try:
        start = datetime.fromisoformat(str(start_raw)).date()
        return max(0, (date.today() - start).days)
    except Exception:
        return 0


def get_guard_context(state_path: Path = DEFAULT_STATE_PATH) -> dict[str, Any]:
    """Return dynamic risk constraints for mandatory trade validation."""
    state = _load_state(state_path)

    if _truthy(os.getenv("NORTH_STAR_GUARD_OVERRIDE", "")):
        return {
            "enabled": True,
            "mode": "override",
            "max_position_pct": 0.05,
            "block_new_positions": False,
            "block_reason": "",
            "reasons": ["NORTH_STAR_GUARD_OVERRIDE enabled"],
        }

    paper_account = state.get("paper_account", {}) if isinstance(state, dict) else {}
    paper_trading = state.get("paper_trading", {}) if isinstance(state, dict) else {}
    portfolio = state.get("portfolio", {}) if isinstance(state, dict) else {}
    weekly_gate = state.get("north_star_weekly_gate", {}) if isinstance(state, dict) else {}
    autopilot = state.get("north_star_autopilot", {}) if isinstance(state, dict) else {}

    equity = _as_float(paper_account.get("equity"), 0.0)
    if equity <= 0:
        equity = _as_float(portfolio.get("equity"), 0.0)

    win_rate = _as_float(paper_account.get("win_rate"), 0.0)
    sample_size = _as_int(paper_account.get("win_rate_sample_size"), 0)
    current_day = _resolve_current_day(paper_trading)
    target_days = _as_int(paper_trading.get("target_duration_days"), DEFAULT_PAPER_DAYS)

    # Default guard = conservative validation mode.
    mode = "validation"
    max_position_pct = 0.025
    block_new_positions = False
    reasons: list[str] = []

    if sample_size >= DEFAULT_MIN_SAMPLE_SIZE and win_rate < 75.0:
        mode = "capital_preservation"
        max_position_pct = 0.01
        block_new_positions = True
        reasons.append(
            f"Win rate {win_rate:.1f}% across {sample_size} trades is below 75% hard floor."
        )
    elif sample_size >= DEFAULT_MIN_SAMPLE_SIZE and win_rate < DEFAULT_TARGET_WIN_RATE:
        mode = "under_target"
        max_position_pct = 0.02
        reasons.append(
            f"Win rate {win_rate:.1f}% across {sample_size} trades is below {DEFAULT_TARGET_WIN_RATE:.0f}% target."
        )
    elif current_day < target_days or sample_size < DEFAULT_MIN_SAMPLE_SIZE:
        mode = "validation"
        max_position_pct = 0.025
        reasons.append(
            f"Paper validation incomplete (day {current_day}/{target_days}, samples {sample_size}/{DEFAULT_MIN_SAMPLE_SIZE})."
        )
    else:
        mode = "scale_ready"
        max_position_pct = 0.05
        reasons.append("Paper validation passed (days + sample size + win-rate threshold).")

    # Weekly operating gate can further cap risk-on size or pause new entries.
    if isinstance(weekly_gate, dict):
        weekly_mode = str(weekly_gate.get("mode", "unknown"))
        weekly_limit = _as_float(weekly_gate.get("recommended_max_position_pct"), 0.0)
        if weekly_limit > 0:
            max_position_pct = min(max_position_pct, weekly_limit)
            reasons.append(
                f"Weekly gate ({weekly_mode}) caps max position size at {weekly_limit * 100:.1f}%."
            )

        if weekly_gate.get("block_new_positions"):
            block_new_positions = True
            weekly_reason = str(weekly_gate.get("reason") or "").strip()
            if weekly_reason:
                reasons.append(f"Weekly gate block: {weekly_reason}")

        cadence = weekly_gate.get("cadence_kpi")
        cadence_present = isinstance(cadence, dict) and "passed" in cadence
        cadence_passed = bool(cadence.get("passed")) if cadence_present else True
        expectancy_present = "expectancy_per_trade" in weekly_gate
        expectancy = _as_float(weekly_gate.get("expectancy_per_trade"), 0.0)
        if cadence_present and not cadence_passed and not block_new_positions:
            max_position_pct = min(max_position_pct, 0.015)
            reasons.append("Cadence KPI not passed; keep position sizing in conservative mode.")
        if expectancy_present and expectancy <= 0 and not block_new_positions:
            max_position_pct = min(max_position_pct, 0.02)
            reasons.append("Weekly expectancy is non-positive; keep risk-on size conservative.")

    # Optional autopilot cap (generated from regime/macro multipliers).
    if isinstance(autopilot, dict):
        tuned = autopilot.get("regime_aware_sizing", {})
        if isinstance(tuned, dict):
            tuned_cap = _as_float(tuned.get("recommended_max_position_pct"), 0.0)
            if tuned_cap > 0:
                max_position_pct = min(max_position_pct, tuned_cap)
                reasons.append(
                    f"Autopilot regime-aware sizing caps max position size at {tuned_cap * 100:.2f}%."
                )

    block_reason = ""
    if block_new_positions:
        if isinstance(weekly_gate, dict) and weekly_gate.get("block_new_positions"):
            block_reason = (
                "North Star guard: weekly operating gate blocked new position openings "
                f"({weekly_gate.get('mode', 'unknown')})."
            )
        else:
            block_reason = (
                "North Star guard: new position openings blocked in capital preservation mode "
                f"(win_rate={win_rate:.1f}%, sample_size={sample_size})."
            )

    return {
        "enabled": True,
        "mode": mode,
        "max_position_pct": round(max_position_pct, 4),
        "block_new_positions": block_new_positions,
        "block_reason": block_reason,
        "win_rate": win_rate,
        "sample_size": sample_size,
        "paper_day": current_day,
        "paper_target_days": target_days,
        "equity": equity,
        "required_cagr_to_target_capital": None,
        "north_star_target_mode": DEFAULT_TARGET_MODE,
        "north_star_monthly_after_tax_target": round(DEFAULT_MONTHLY_AFTER_TAX_TARGET, 2),
        "target_capital": DEFAULT_TARGET_CAPITAL,
        "target_date": None,
        "weekly_gate_mode": weekly_gate.get("mode")
        if isinstance(weekly_gate, dict)
        else "unavailable",
        "reasons": reasons,
    }

"""Behavioral Guard - Prevents emotion-driven trading mistakes.

Checks:
1. FOMO: Reject IC entries when SPY moved >2% intraday (inflated premiums, unclear direction)
2. Stop-loss cooling: 24h wait after stop-loss exit before re-entering same expiry
3. Blacklist: Belt+suspenders check against TargetSymbols.BLACKLIST

Fails open (allow) when data unavailable — other gates (IV rank, position size) still protect.
"""

from __future__ import annotations

import json
import logging
from dataclasses import dataclass, field
from datetime import datetime, timedelta
from pathlib import Path

from src.core.trading_constants import (
    FOMO_INTRADAY_MOVE_PCT,
    STOP_LOSS_COOLING_HOURS,
    extract_underlying,
)

logger = logging.getLogger(__name__)

_STATE_PATH = Path(__file__).parent.parent.parent / "data" / "behavioral_guard_state.json"


@dataclass
class BehavioralCheckResult:
    """Result of behavioral guard evaluation."""

    passed: bool
    checks_run: list[str] = field(default_factory=list)
    rejections: list[str] = field(default_factory=list)
    warnings: list[str] = field(default_factory=list)


class BehavioralGuard:
    """Prevents emotion-driven trading mistakes."""

    @staticmethod
    def evaluate(
        symbol: str, expiry: str | None = None, spy_change_pct: float | None = None
    ) -> BehavioralCheckResult:
        """Run all behavioral checks.

        Args:
            symbol: Ticker or OCC option symbol.
            expiry: Expiry date string (YYYY-MM-DD) for cooling check.
            spy_change_pct: Absolute intraday SPY move as decimal (e.g. 0.025 = 2.5%).
                           Pass None if unavailable (fails open).

        Returns:
            BehavioralCheckResult with pass/fail and details.
        """
        checks_run: list[str] = []
        rejections: list[str] = []
        warnings: list[str] = []

        # 1. FOMO check
        checks_run.append("fomo_intraday_move")
        if spy_change_pct is not None:
            if abs(spy_change_pct) >= FOMO_INTRADAY_MOVE_PCT:
                rejections.append(
                    f"FOMO blocked: SPY moved {abs(spy_change_pct) * 100:.1f}% intraday "
                    f"(threshold: {FOMO_INTRADAY_MOVE_PCT * 100:.0f}%). "
                    f"Premiums inflated, direction unclear."
                )
        else:
            warnings.append("FOMO check skipped: no intraday data available (fails open)")

        # 2. Stop-loss cooling
        checks_run.append("stop_loss_cooling")
        if expiry:
            cooling_msg = BehavioralGuard._check_cooling(expiry)
            if cooling_msg:
                rejections.append(cooling_msg)

        # 3. Blacklist
        checks_run.append("blacklist")
        underlying = extract_underlying(symbol)
        blacklist_msg = BehavioralGuard._check_blacklist(underlying)
        if blacklist_msg:
            rejections.append(blacklist_msg)

        return BehavioralCheckResult(
            passed=len(rejections) == 0,
            checks_run=checks_run,
            rejections=rejections,
            warnings=warnings,
        )

    @staticmethod
    def _check_cooling(expiry: str) -> str | None:
        """Check if expiry is in cooling period after a recent stop-loss."""
        state = BehavioralGuard._load_state()
        now = datetime.now()
        cooling_cutoff = now - timedelta(hours=STOP_LOSS_COOLING_HOURS)

        for entry in state.get("stop_loss_exits", []):
            if entry.get("expiry") != expiry:
                continue
            exit_time = datetime.fromisoformat(entry["timestamp"])
            if exit_time > cooling_cutoff:
                hours_ago = (now - exit_time).total_seconds() / 3600
                remaining = STOP_LOSS_COOLING_HOURS - hours_ago
                return (
                    f"Cooling period: stop-loss on expiry {expiry} was {hours_ago:.0f}h ago. "
                    f"Wait {remaining:.0f}h more (policy: {STOP_LOSS_COOLING_HOURS}h)."
                )
        return None

    @staticmethod
    def _check_blacklist(underlying: str) -> str | None:
        """Belt+suspenders blacklist check."""
        try:
            from src.constants.trading_thresholds import TargetSymbols

            if underlying.upper() in [s.upper() for s in TargetSymbols.BLACKLIST]:
                return f"Blacklisted ticker: {underlying} is in TargetSymbols.BLACKLIST"
        except ImportError:
            pass  # No blacklist module = no block
        return None

    @staticmethod
    def record_stop_loss_exit(expiry: str) -> None:
        """Record a stop-loss exit for cooling enforcement.

        Call this from the position manager when a stop-loss triggers.
        """
        state = BehavioralGuard._load_state()
        exits = state.get("stop_loss_exits", [])
        exits.append(
            {
                "expiry": expiry,
                "timestamp": datetime.now().isoformat(),
            }
        )
        # Prune entries older than 48h
        cutoff = datetime.now() - timedelta(hours=48)
        exits = [e for e in exits if datetime.fromisoformat(e["timestamp"]) > cutoff]
        state["stop_loss_exits"] = exits
        BehavioralGuard._save_state(state)
        logger.info(
            f"Recorded stop-loss exit for expiry {expiry} (cooling: {STOP_LOSS_COOLING_HOURS}h)"
        )

    @staticmethod
    def _load_state() -> dict:
        try:
            if _STATE_PATH.exists():
                with open(_STATE_PATH) as f:
                    return json.load(f)
        except Exception as e:
            logger.warning(f"Could not load behavioral guard state: {e}")
        return {"stop_loss_exits": []}

    @staticmethod
    def _save_state(state: dict) -> None:
        try:
            _STATE_PATH.parent.mkdir(parents=True, exist_ok=True)
            with open(_STATE_PATH, "w") as f:
                json.dump(state, f, indent=2)
        except Exception as e:
            logger.warning(f"Could not save behavioral guard state: {e}")

