"""
Retry Logic with Exponential Backoff.

Provides reliable retry mechanisms for transient failures.

Created: Jan 19, 2026 (LL-249)
"""

from __future__ import annotations

import logging
import random
import time
from dataclasses import dataclass
from functools import wraps
from typing import Any, Callable, TypeVar

logger = logging.getLogger(__name__)

T = TypeVar("T")


@dataclass
class RetryConfig:
    """Configuration for retry behavior."""

    max_attempts: int = 4
    base_delay: float = 2.0  # Initial delay in seconds
    max_delay: float = 60.0  # Maximum delay
    exponential_base: float = 2.0
    jitter: bool = True  # Add randomness to prevent thundering herd
    retryable_exceptions: tuple[type[Exception], ...] = (Exception,)


def retry_with_backoff(
    config: RetryConfig | None = None,
    max_attempts: int = 4,
    base_delay: float = 2.0,
    retryable_exceptions: tuple[type[Exception], ...] = (Exception,),
) -> Callable[[Callable[..., T]], Callable[..., T]]:
    """
    Decorator for retrying functions with exponential backoff.

    Usage:
        @retry_with_backoff(max_attempts=4, base_delay=2.0)
        def call_api():
            return requests.get(url)

    Or with config:
        config = RetryConfig(max_attempts=5, base_delay=1.0)
        @retry_with_backoff(config=config)
        def risky_operation():
            ...
    """
    if config is None:
        config = RetryConfig(
            max_attempts=max_attempts,
            base_delay=base_delay,
            retryable_exceptions=retryable_exceptions,
        )

    def decorator(func: Callable[..., T]) -> Callable[..., T]:
        @wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> T:
            last_exception: Exception | None = None

            for attempt in range(1, config.max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except config.retryable_exceptions as e:
                    last_exception = e

                    if attempt == config.max_attempts:
                        logger.error(
                            f"[{func.__name__}] All {config.max_attempts} attempts failed. "
                            f"Last error: {e}"
                        )
                        raise

                    # Calculate delay with exponential backoff
                    delay = min(
                        config.base_delay * (config.exponential_base ** (attempt - 1)),
                        config.max_delay,
                    )

                    # Add jitter (±25%)
                    if config.jitter:
                        delay *= 0.75 + random.random() * 0.5

                    logger.warning(
                        f"[{func.__name__}] Attempt {attempt}/{config.max_attempts} failed: {e}. "
                        f"Retrying in {delay:.1f}s..."
                    )
                    time.sleep(delay)

            # Should not reach here, but just in case
            if last_exception:
                raise last_exception
            raise RuntimeError(f"Unexpected state in retry for {func.__name__}")

        return wrapper

    return decorator


class RetryableOperation:
    """
    Context manager for retryable operations.

    Usage:
        with RetryableOperation(max_attempts=3, base_delay=1.0) as retry:
            for attempt in retry:
                try:
                    result = risky_operation()
                    break  # Success
                except SomeError as e:
                    retry.record_failure(e)
    """

    def __init__(
        self,
        max_attempts: int = 4,
        base_delay: float = 2.0,
        max_delay: float = 60.0,
        operation_name: str = "operation",
    ):
        self.max_attempts = max_attempts
        self.base_delay = base_delay
        self.max_delay = max_delay
        self.operation_name = operation_name
        self._attempt = 0
        self._last_error: Exception | None = None

    def __enter__(self) -> RetryableOperation:
        return self

    def __exit__(self, _exc_type: Any, _exc_val: Any, _exc_tb: Any) -> None:
        # Don't suppress exceptions - let them propagate
        pass

    def __iter__(self):
        """Iterate through retry attempts."""
        for attempt in range(1, self.max_attempts + 1):
            self._attempt = attempt
            yield attempt

    def record_failure(self, error: Exception) -> None:
        """Record a failure and sleep before next attempt."""
        self._last_error = error

        if self._attempt >= self.max_attempts:
            logger.error(
                f"[{self.operation_name}] All {self.max_attempts} attempts exhausted. "
                f"Last error: {error}"
            )
            raise error

        delay = min(self.base_delay * (2 ** (self._attempt - 1)), self.max_delay)
        delay *= 0.75 + random.random() * 0.5  # Jitter

        logger.warning(
            f"[{self.operation_name}] Attempt {self._attempt}/{self.max_attempts} failed: {error}. "
            f"Retrying in {delay:.1f}s..."
        )
        time.sleep(delay)

    @property
    def attempt(self) -> int:
        """Current attempt number."""
        return self._attempt

    @property
    def last_error(self) -> Exception | None:
        """Last recorded error."""
        return self._last_error

"""
Self-Healing System Monitor.

Automatically detects and fixes common issues in the trading system.

Health Checks:
1. Data integrity (JSON files, system state)
2. API connectivity (Alpaca, LanceDB)
3. Position compliance (CLAUDE.md rules)
4. Stale data detection
5. Configuration drift

Auto-Fix Capabilities:
- Regenerate corrupt JSON files
- Reset circuit breakers
- Sync stale data
- Clean up deprecated files

Created: Jan 19, 2026 (LL-249: Resilience and Self-Healing)
"""

from __future__ import annotations

import json
import logging
import os
from dataclasses import dataclass, field
from datetime import datetime, timedelta
from enum import Enum
from pathlib import Path
from typing import Any, Callable

logger = logging.getLogger(__name__)


class HealthStatus(Enum):
    """Health check status."""

    HEALTHY = "healthy"
    DEGRADED = "degraded"
    UNHEALTHY = "unhealthy"
    HEALED = "healed"  # Was unhealthy, auto-fixed


@dataclass
class HealthCheck:
    """Result of a health check."""

    name: str
    status: HealthStatus
    message: str
    details: dict = field(default_factory=dict)
    auto_fixed: bool = False
    fix_action: str | None = None


class SelfHealer:
    """
    Self-healing system monitor.

    Usage:
        healer = SelfHealer(project_root="/home/user/trading")
        results = healer.run_all_checks()

        # Auto-fix issues
        healer.heal()

        # Get summary
        print(healer.get_summary())
    """

    def __init__(self, project_root: str | Path | None = None):
        self.project_root = Path(project_root or os.getcwd())
        self.checks: list[HealthCheck] = []
        self._healers: dict[str, Callable[[], bool]] = {}

    def run_all_checks(self) -> list[HealthCheck]:
        """Run all health checks."""
        self.checks = []

        # Data integrity checks
        self.checks.append(self._check_system_state())
        self.checks.append(self._check_json_files())

        # Configuration checks
        self.checks.append(self._check_env_vars())
        self.checks.append(self._check_claude_md())

        # Staleness checks
        self.checks.append(self._check_data_freshness())

        # Compliance checks
        self.checks.append(self._check_position_compliance())

        return self.checks

    def _check_system_state(self) -> HealthCheck:
        """Check system_state.json integrity."""
        state_file = self.project_root / "data" / "system_state.json"

        if not state_file.exists():
            return HealthCheck(
                name="system_state",
                status=HealthStatus.UNHEALTHY,
                message="system_state.json not found",
                details={"path": str(state_file)},
            )

        try:
            with open(state_file) as f:
                data = json.load(f)

            # Validate required fields
            required = ["portfolio", "positions", "trade_history"]
            missing = [k for k in required if k not in data]

            if missing:
                return HealthCheck(
                    name="system_state",
                    status=HealthStatus.DEGRADED,
                    message=f"Missing required fields: {missing}",
                    details={"missing_fields": missing},
                )

            return HealthCheck(
                name="system_state",
                status=HealthStatus.HEALTHY,
                message="system_state.json is valid",
                details={
                    "equity": data.get("portfolio", {}).get("equity"),
                    "positions_count": len(data.get("positions", [])),
                    "trades_count": len(data.get("trade_history", [])),
                },
            )

        except json.JSONDecodeError as e:
            self._healers["system_state"] = self._heal_corrupt_json
            return HealthCheck(
                name="system_state",
                status=HealthStatus.UNHEALTHY,
                message=f"Corrupt JSON: {e}",
                details={"error": str(e), "can_heal": True},
            )

    def _check_json_files(self) -> HealthCheck:
        """Check all JSON files for corruption."""
        data_dir = self.project_root / "data"
        corrupt_files = []
        valid_count = 0

        for json_file in data_dir.glob("*.json"):
            try:
                with open(json_file) as f:
                    json.load(f)
                valid_count += 1
            except json.JSONDecodeError:
                corrupt_files.append(str(json_file.name))

        if corrupt_files:
            return HealthCheck(
                name="json_files",
                status=HealthStatus.UNHEALTHY,
                message=f"Corrupt JSON files: {corrupt_files}",
                details={"corrupt": corrupt_files, "valid": valid_count},
            )

        return HealthCheck(
            name="json_files",
            status=HealthStatus.HEALTHY,
            message=f"All {valid_count} JSON files are valid",
            details={"valid_count": valid_count},
        )

    def _check_env_vars(self) -> HealthCheck:
        """Check critical environment variables."""
        required = [
            "ALPACA_PAPER_TRADING_5K_API_KEY",
            "ALPACA_PAPER_TRADING_5K_API_SECRET",
        ]

        # Check in .env file or environment
        missing = []
        for var in required:
            if not os.getenv(var):
                missing.append(var)

        if missing:
            return HealthCheck(
                name="env_vars",
                status=HealthStatus.DEGRADED,
                message=f"Missing env vars: {missing}",
                details={"missing": missing},
            )

        return HealthCheck(
            name="env_vars",
            status=HealthStatus.HEALTHY,
            message="All required environment variables set",
        )

    def _check_claude_md(self) -> HealthCheck:
        """Check CLAUDE.md exists and has required sections."""
        claude_md = self.project_root / ".claude" / "CLAUDE.md"

        if not claude_md.exists():
            return HealthCheck(
                name="claude_md",
                status=HealthStatus.UNHEALTHY,
                message="CLAUDE.md not found",
            )

        content = claude_md.read_text()
        required_sections = ["## Strategy", "iron condor", "SPY"]

        missing = [s for s in required_sections if s.lower() not in content.lower()]

        if missing:
            return HealthCheck(
                name="claude_md",
                status=HealthStatus.DEGRADED,
                message=f"CLAUDE.md missing sections: {missing}",
                details={"missing": missing},
            )

        return HealthCheck(
            name="claude_md",
            status=HealthStatus.HEALTHY,
            message="CLAUDE.md is properly configured",
        )

    def _check_data_freshness(self) -> HealthCheck:
        """Check if data is stale."""
        state_file = self.project_root / "data" / "system_state.json"

        if not state_file.exists():
            return HealthCheck(
                name="data_freshness",
                status=HealthStatus.UNHEALTHY,
                message="No data file to check",
            )

        try:
            with open(state_file) as f:
                data = json.load(f)

            last_updated = data.get("last_updated")
            if not last_updated:
                return HealthCheck(
                    name="data_freshness",
                    status=HealthStatus.DEGRADED,
                    message="No last_updated timestamp",
                )

            # Parse timestamp
            if last_updated.endswith("Z"):
                last_updated = last_updated[:-1] + "+00:00"

            updated_dt = datetime.fromisoformat(last_updated.replace("Z", "+00:00"))
            now = datetime.now(updated_dt.tzinfo)
            age = now - updated_dt

            # Check staleness thresholds
            if age > timedelta(hours=24):
                self._healers["data_freshness"] = self._heal_stale_data
                return HealthCheck(
                    name="data_freshness",
                    status=HealthStatus.UNHEALTHY,
                    message=f"Data is {age.total_seconds() / 3600:.1f} hours old",
                    details={"age_hours": age.total_seconds() / 3600, "can_heal": True},
                )
            elif age > timedelta(hours=4):
                return HealthCheck(
                    name="data_freshness",
                    status=HealthStatus.DEGRADED,
                    message=f"Data is {age.total_seconds() / 3600:.1f} hours old",
                    details={"age_hours": age.total_seconds() / 3600},
                )

            return HealthCheck(
                name="data_freshness",
                status=HealthStatus.HEALTHY,
                message=f"Data is {age.total_seconds() / 60:.0f} minutes old",
                details={"age_minutes": age.total_seconds() / 60},
            )

        except Exception as e:
            return HealthCheck(
                name="data_freshness",
                status=HealthStatus.DEGRADED,
                message=f"Could not check freshness: {e}",
            )

    def _check_position_compliance(self) -> HealthCheck:
        """Check positions comply with CLAUDE.md rules."""
        state_file = self.project_root / "data" / "system_state.json"

        if not state_file.exists():
            return HealthCheck(
                name="position_compliance",
                status=HealthStatus.DEGRADED,
                message="No system state to check",
            )

        try:
            # Import canonical constants
            import sys

            sys.path.insert(0, str(self.project_root))
            from src.core.trading_constants import ALLOWED_TICKERS, MAX_POSITION_PCT, MAX_POSITIONS

            with open(state_file) as f:
                data = json.load(f)

            positions = data.get("positions", [])
            equity = data.get("portfolio", {}).get("equity", 5000)
            max_position_value = equity * MAX_POSITION_PCT

            violations = []

            # Check position count (max from canonical constants)
            if len(positions) > MAX_POSITIONS:
                violations.append(f"Position count {len(positions)} > {MAX_POSITIONS} max")

            # Check position values
            for pos in positions:
                value = abs(pos.get("value", 0))
                symbol = pos.get("symbol", "UNKNOWN")

                if value > max_position_value:
                    violations.append(
                        f"{symbol} value ${value:.2f} > ${max_position_value:.2f} ({MAX_POSITION_PCT * 100}% limit)"
                    )

                # Check against canonical ticker whitelist
                underlying = symbol[:3] if len(symbol) > 3 else symbol
                if underlying not in ALLOWED_TICKERS:
                    violations.append(
                        f"{symbol} not in allowed tickers (canonical: {sorted(ALLOWED_TICKERS)})"
                    )

            if violations:
                return HealthCheck(
                    name="position_compliance",
                    status=HealthStatus.UNHEALTHY,
                    message=f"{len(violations)} compliance violations",
                    details={"violations": violations},
                )

            return HealthCheck(
                name="position_compliance",
                status=HealthStatus.HEALTHY,
                message="All positions comply with CLAUDE.md",
                details={"position_count": len(positions)},
            )

        except Exception as e:
            return HealthCheck(
                name="position_compliance",
                status=HealthStatus.DEGRADED,
                message=f"Could not check compliance: {e}",
            )

    def _heal_corrupt_json(self) -> bool:
        """Attempt to heal corrupt JSON by restoring from backup."""
        state_file = self.project_root / "data" / "system_state.json"
        backup_dir = self.project_root / "data" / "backups"

        # Find most recent backup
        backups = sorted(backup_dir.glob("system_state_*.json"), reverse=True)

        if not backups:
            logger.error("No backups found to restore from")
            return False

        latest_backup = backups[0]
        try:
            # Validate backup
            with open(latest_backup) as f:
                data = json.load(f)

            # Restore
            with open(state_file, "w") as f:
                json.dump(data, f, indent=2)

            logger.info(f"Restored system_state.json from {latest_backup.name}")
            return True

        except Exception as e:
            logger.error(f"Failed to restore from backup: {e}")
            return False

    def _heal_stale_data(self) -> bool:
        """Trigger data sync to heal stale data."""
        logger.info("Triggering data sync to heal stale data...")
        # This would typically trigger a GitHub Actions workflow or API call
        # For now, log the intent
        return False  # Manual intervention needed

    def heal(self) -> list[HealthCheck]:
        """Attempt to auto-fix all healable issues."""
        healed = []

        for check in self.checks:
            if check.status == HealthStatus.UNHEALTHY and check.name in self._healers:
                healer = self._healers[check.name]
                try:
                    if healer():
                        check.status = HealthStatus.HEALED
                        check.auto_fixed = True
                        check.fix_action = healer.__name__
                        healed.append(check)
                        logger.info(f"Auto-healed: {check.name}")
                except Exception as e:
                    logger.error(f"Failed to heal {check.name}: {e}")

        return healed

    def get_summary(self) -> dict[str, Any]:
        """Get summary of all health checks."""
        by_status = {status.value: 0 for status in HealthStatus}

        for check in self.checks:
            by_status[check.status.value] += 1

        overall = HealthStatus.HEALTHY
        if by_status["unhealthy"] > 0:
            overall = HealthStatus.UNHEALTHY
        elif by_status["degraded"] > 0:
            overall = HealthStatus.DEGRADED

        return {
            "overall_status": overall.value,
            "total_checks": len(self.checks),
            "by_status": by_status,
            "checks": [
                {
                    "name": c.name,
                    "status": c.status.value,
                    "message": c.message,
                    "auto_fixed": c.auto_fixed,
                }
                for c in self.checks
            ],
            "timestamp": datetime.utcnow().isoformat() + "Z",
        }

    def get_report(self) -> str:
        """Get human-readable health report."""
        lines = [
            "=" * 60,
            "SELF-HEALING HEALTH CHECK REPORT",
            "=" * 60,
            "",
        ]

        summary = self.get_summary()
        lines.append(f"Overall Status: {summary['overall_status'].upper()}")
        lines.append(f"Total Checks: {summary['total_checks']}")
        lines.append("")

        for check in self.checks:
            status_icon = {
                HealthStatus.HEALTHY: "✅",
                HealthStatus.DEGRADED: "⚠️",
                HealthStatus.UNHEALTHY: "❌",
                HealthStatus.HEALED: "🔧",
            }.get(check.status, "❓")

            lines.append(f"{status_icon} {check.name}: {check.message}")
            if check.auto_fixed:
                lines.append(f"   └─ Auto-fixed via {check.fix_action}")

        lines.append("")
        lines.append("=" * 60)

        return "\n".join(lines)

"""LLM budget enforcement for Gate 3."""

from __future__ import annotations

import logging

logger = logging.getLogger(__name__)


class BudgetController:
    """
    Tracks estimated LLM spend for a single run.

    We assume Actions reset state each execution so a per-run counter is enough.
    """

    def __init__(
        self,
        max_run_spend: float = 1.50,
        default_estimate: float = 0.01,
        model_costs: dict[str, float] | None = None,
    ) -> None:
        self.max_run_spend = max_run_spend
        self.default_estimate = default_estimate
        self.model_costs = model_costs or {}
        self.current_spend = 0.0

    def can_afford_execution(
        self,
        *,
        model: str | None = None,
        estimate: float | None = None,
    ) -> bool:
        """Return True if we can spend at least `estimate` more dollars."""
        expected = estimate
        if expected is None:
            expected = self.model_costs.get(model or "", self.default_estimate)

        allowed = self.current_spend + expected <= self.max_run_spend
        if not allowed:
            logger.warning(
                "LLM budget exhausted: need %.2f but only %.2f remaining.",
                expected,
                self.remaining_budget,
            )
        return allowed

    def log_spend(self, amount: float) -> None:
        """Record an actual spend after a successful API call."""
        if amount <= 0:
            return
        self.current_spend += amount
        logger.info(
            "LLM budget updated: +$%.4f (total this run: $%.4f)",
            amount,
            self.current_spend,
        )

    @property
    def remaining_budget(self) -> float:
        return max(0.0, self.max_run_spend - self.current_spend)

"""Profit target tracker for daily income and budget scaling recommendations."""

from __future__ import annotations

import json
import os
from dataclasses import asdict, dataclass, field
from datetime import datetime, timezone
from pathlib import Path
from typing import Any

try:
    from src.core.trading_constants import NORTH_STAR_DAILY_AFTER_TAX
except Exception:
    NORTH_STAR_DAILY_AFTER_TAX = 200.0


def _as_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(value)
    except (TypeError, ValueError):
        return default


def _as_int(value: Any, default: int = 0) -> int:
    try:
        return int(value)
    except (TypeError, ValueError):
        return default


def _load_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    try:
        with path.open("r", encoding="utf-8") as handle:
            payload = json.load(handle)
        return payload if isinstance(payload, dict) else {}
    except Exception:
        return {}


@dataclass
class ProfitTargetPlan:
    """Computed progress and budget recommendations toward daily profit goal."""

    current_daily_profit: float
    projected_daily_profit: float
    target_daily_profit: float
    target_gap: float
    current_daily_budget: float
    recommended_daily_budget: float | None
    scaling_factor: float | None
    avg_return_pct: float
    win_rate: float
    actions: list[str] = field(default_factory=list)
    recommended_allocations: dict[str, float] = field(default_factory=dict)
    generated_at: str = field(default_factory=lambda: datetime.now(timezone.utc).isoformat())

    def to_dict(self) -> dict[str, Any]:
        return asdict(self)


class ProfitTargetTracker:
    """Compute a practical scaling plan from current paper-trading evidence."""

    def __init__(
        self,
        target_daily_profit: float | None = None,
        *,
        state_path: Path | None = None,
    ) -> None:
        self.target_daily_profit = float(
            target_daily_profit if target_daily_profit is not None else NORTH_STAR_DAILY_AFTER_TAX
        )
        self.state_path = state_path or Path(
            os.getenv("SYSTEM_STATE_PATH", "data/system_state.json")
        )

    def _load_state(self) -> dict[str, Any]:
        return _load_json(self.state_path)

    def _resolve_current_budget(self, state: dict[str, Any]) -> float:
        env_budget = os.getenv("DAILY_INVESTMENT")
        if env_budget is not None:
            parsed = _as_float(env_budget, 0.0)
            if parsed > 0:
                return parsed

        risk = state.get("risk", {}) if isinstance(state, dict) else {}
        risk_budget = _as_float(risk.get("daily_budget"), 0.0)
        if risk_budget > 0:
            return risk_budget

        # Derive from account risk envelope when explicit daily budget is unavailable.
        paper = state.get("paper_account", {}) if isinstance(state, dict) else {}
        paper_equity = _as_float(paper.get("equity"), 0.0)
        if paper_equity > 0:
            return round(paper_equity * 0.05, 2)

        # Conservative fallback used when we cannot infer equity.
        return 25.0

    def generate_plan(self) -> ProfitTargetPlan:
        state = self._load_state()
        paper = state.get("paper_account", {}) if isinstance(state, dict) else {}
        paper_trading = state.get("paper_trading", {}) if isinstance(state, dict) else {}

        current_daily_profit = _as_float(paper.get("daily_change"), 0.0)
        total_pl = _as_float(paper.get("total_pl"), 0.0)
        win_rate = _as_float(paper.get("win_rate"), 0.0)
        paper_day = max(1, _as_int(paper_trading.get("current_day"), 0))
        average_daily_profit = total_pl / paper_day

        # Blend today's result with long-horizon average to avoid overreacting.
        projected_daily_profit = (0.6 * average_daily_profit) + (0.4 * current_daily_profit)

        current_daily_budget = self._resolve_current_budget(state)
        if current_daily_budget > 0:
            avg_return_pct = (average_daily_profit / current_daily_budget) * 100.0
        else:
            avg_return_pct = 0.0

        target_gap = self.target_daily_profit - projected_daily_profit

        recommended_daily_budget: float | None = None
        scaling_factor: float | None = None
        if avg_return_pct > 0:
            recommended_daily_budget = self.target_daily_profit / (avg_return_pct / 100.0)
            scaling_factor = (
                recommended_daily_budget / current_daily_budget
                if current_daily_budget > 0
                else None
            )

        actions: list[str] = []
        if win_rate < 80.0:
            actions.append(
                f"Keep risk constrained until win rate improves (current {win_rate:.1f}% vs 80% target)."
            )

        if avg_return_pct <= 0:
            actions.append("Do not scale budget yet; improve expectancy and daily edge first.")
        elif target_gap > 0:
            actions.append(
                f"Projected daily profit is ${target_gap:.2f} below target; scale budget gradually."
            )
            if recommended_daily_budget is not None:
                actions.append(
                    f"Target daily budget: ${recommended_daily_budget:,.2f} "
                    f"({scaling_factor:.2f}x current)."
                )
        else:
            actions.append(
                "Projected daily profit meets target; hold sizing discipline and compound."
            )

        recommended_allocations: dict[str, float] = {}
        if recommended_daily_budget is not None and recommended_daily_budget > 0:
            recommended_allocations = {
                "options_income": round(recommended_daily_budget * 0.70, 2),
                "equity_momentum": round(recommended_daily_budget * 0.20, 2),
                "alternatives": round(recommended_daily_budget * 0.10, 2),
            }

        return ProfitTargetPlan(
            current_daily_profit=round(current_daily_profit, 2),
            projected_daily_profit=round(projected_daily_profit, 2),
            target_daily_profit=round(self.target_daily_profit, 2),
            target_gap=round(target_gap, 2),
            current_daily_budget=round(current_daily_budget, 2),
            recommended_daily_budget=round(recommended_daily_budget, 2)
            if recommended_daily_budget is not None
            else None,
            scaling_factor=round(scaling_factor, 2) if scaling_factor is not None else None,
            avg_return_pct=round(avg_return_pct, 2),
            win_rate=round(win_rate, 2),
            actions=actions,
            recommended_allocations=recommended_allocations,
        )

"""Read-only local ops snapshot for Perplexity Local MCP command connectors."""

from __future__ import annotations

import json
from datetime import UTC, datetime
from pathlib import Path
from typing import Any

SYSTEM_STATE_PATH = Path("data/system_state.json")
VERIFICATION_REPORTS_PATH = Path("data/verification_reports.json")
RAG_INDEX_PATH = Path("data/rag/lessons_query.json")
PUBLICATION_HISTORY_PATH = Path("data/analytics/publication-status-history.jsonl")
LESSONS_PATH = Path("rag_knowledge/lessons_learned")


def build_local_ops_snapshot(repo_root: Path, *, now: datetime | None = None) -> dict[str, Any]:
    """Build an immutable status payload for local AI assistants."""
    now_utc = (now or datetime.now(UTC)).astimezone(UTC)

    system_state_file = repo_root / SYSTEM_STATE_PATH
    verification_file = repo_root / VERIFICATION_REPORTS_PATH
    rag_index_file = repo_root / RAG_INDEX_PATH
    publication_file = repo_root / PUBLICATION_HISTORY_PATH
    lessons_dir = repo_root / LESSONS_PATH

    system_state = _read_json(system_state_file)
    verification_reports = _read_json(verification_file)
    latest_verification = _latest_verification_row(verification_reports)
    latest_publication = _latest_jsonl_row(publication_file)

    system_last_updated = _parse_dt(system_state.get("last_updated"))
    rag_index_updated = _file_mtime_utc(rag_index_file)
    lessons_count = len(list(lessons_dir.glob("*.md"))) if lessons_dir.exists() else 0

    paper_account = system_state.get("paper_account", {})
    positions = system_state.get("positions", [])

    trading = {
        "equity": _pick_first_number(
            paper_account.get("equity"),
            system_state.get("account", {}).get("current_equity"),
            system_state.get("portfolio", {}).get("equity"),
        ),
        "cash": _pick_first_number(
            paper_account.get("cash"),
            system_state.get("account", {}).get("cash"),
            system_state.get("portfolio", {}).get("cash"),
        ),
        "daily_pnl": _pick_first_number(
            paper_account.get("daily_change"),
            latest_verification.get("daily_pnl"),
        ),
        "positions_count": int(len(positions)) if isinstance(positions, list) else 0,
        "system_last_updated_utc": _to_iso(system_last_updated),
        "system_state_age_minutes": _age_minutes(system_last_updated, now_utc),
    }

    verification = {
        "latest_date": latest_verification.get("date"),
        "traded": latest_verification.get("traded"),
        "orders": latest_verification.get("orders"),
        "fills": latest_verification.get("fills"),
        "positions": latest_verification.get("positions"),
        "equity": latest_verification.get("equity"),
        "daily_pnl": latest_verification.get("daily_pnl"),
        "total_pnl": latest_verification.get("total_pnl"),
    }

    publishing = {
        "latest_date": latest_publication.get("date"),
        "latest_generated_at_utc": latest_publication.get("generated_at_utc"),
        "latest_generated_at_et": latest_publication.get("generated_at_et"),
        "platforms": latest_publication.get("platforms", {}),
    }

    rag = {
        "lessons_count": lessons_count,
        "query_index_updated_utc": _to_iso(rag_index_updated),
        "query_index_age_minutes": _age_minutes(rag_index_updated, now_utc),
    }

    health_flags = {
        "system_state_stale": bool(
            trading["system_state_age_minutes"] is None or trading["system_state_age_minutes"] > 180
        ),
        "rag_index_stale": bool(
            rag["query_index_age_minutes"] is None or rag["query_index_age_minutes"] > 1440
        ),
        "verification_missing": not bool(verification.get("latest_date")),
        "publishing_missing": not bool(publishing.get("latest_date")),
    }

    return {
        "generated_at_utc": _to_iso(now_utc),
        "repo_root": str(repo_root),
        "trading": trading,
        "verification": verification,
        "rag": rag,
        "publishing": publishing,
        "health_flags": health_flags,
        "sources": {
            "system_state": _source_meta(system_state_file),
            "verification_reports": _source_meta(verification_file),
            "rag_index": _source_meta(rag_index_file),
            "publication_history": _source_meta(publication_file),
        },
    }


def render_local_ops_markdown(snapshot: dict[str, Any]) -> str:
    """Render a compact markdown status block for chat assistants."""
    trading = snapshot.get("trading", {})
    verification = snapshot.get("verification", {})
    rag = snapshot.get("rag", {})
    publishing = snapshot.get("publishing", {})
    health_flags = snapshot.get("health_flags", {})

    lines = [
        "# Local Ops Snapshot",
        "",
        f"- Generated (UTC): `{snapshot.get('generated_at_utc', 'N/A')}`",
        "",
        "## Trading",
        f"- Equity: `{trading.get('equity')}`",
        f"- Cash: `{trading.get('cash')}`",
        f"- Daily P/L: `{trading.get('daily_pnl')}`",
        f"- Positions: `{trading.get('positions_count')}`",
        f"- System last updated (UTC): `{trading.get('system_last_updated_utc')}`",
        f"- System age (minutes): `{trading.get('system_state_age_minutes')}`",
        "",
        "## Verification",
        f"- Latest report date: `{verification.get('latest_date')}`",
        f"- Traded: `{verification.get('traded')}`",
        f"- Orders/Fills: `{verification.get('orders')}` / `{verification.get('fills')}`",
        f"- Verification daily P/L: `{verification.get('daily_pnl')}`",
        "",
        "## RAG",
        f"- Lessons count: `{rag.get('lessons_count')}`",
        f"- Query index updated (UTC): `{rag.get('query_index_updated_utc')}`",
        f"- Query index age (minutes): `{rag.get('query_index_age_minutes')}`",
        "",
        "## Publishing",
        f"- Latest publication date: `{publishing.get('latest_date')}`",
        f"- Latest generated (UTC): `{publishing.get('latest_generated_at_utc')}`",
        "",
        "## Health Flags",
