    ]
    return "\n".join(lines) + "\n"


def _read_json(path: Path) -> dict[str, Any] | list[Any]:
    if not path.exists():
        return {}
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
        if isinstance(payload, (dict, list)):
            return payload
        return {}
    except Exception:
        return {}


def _latest_verification_row(payload: dict[str, Any] | list[Any]) -> dict[str, Any]:
    if isinstance(payload, list):
        rows = [row for row in payload if isinstance(row, dict)]
        if not rows:
            return {}
        return rows[-1]
    if isinstance(payload, dict):
        return payload
    return {}


def _latest_jsonl_row(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    latest: dict[str, Any] = {}
    for line in path.read_text(encoding="utf-8").splitlines():
        text = line.strip()
        if not text:
            continue
        try:
            payload = json.loads(text)
        except json.JSONDecodeError:
            continue
        if isinstance(payload, dict):
            latest = payload
    return latest


def _source_meta(path: Path) -> dict[str, Any]:
    mtime = _file_mtime_utc(path)
    return {
        "exists": path.exists(),
        "mtime_utc": _to_iso(mtime),
    }


def _parse_dt(value: Any) -> datetime | None:
    if not value or not isinstance(value, str):
        return None
    try:
        text = value.replace("Z", "+00:00")
        return datetime.fromisoformat(text).astimezone(UTC)
    except ValueError:
        return None


def _file_mtime_utc(path: Path) -> datetime | None:
    if not path.exists():
        return None
    return datetime.fromtimestamp(path.stat().st_mtime, tz=UTC)


def _to_iso(value: datetime | None) -> str | None:
    if value is None:
        return None
    return value.astimezone(UTC).isoformat().replace("+00:00", "Z")


def _age_minutes(value: datetime | None, now_utc: datetime) -> float | None:
    if value is None:
        return None
    return round((now_utc - value).total_seconds() / 60.0, 3)


def _pick_first_number(*values: Any) -> float | None:
    for value in values:
        if value is None:
            continue
        try:
            return float(value)
        except (TypeError, ValueError):
            continue
    return None

